CREATE 
VIEW `browsereg`AS 
select `kalmut_registeredunit`.`rowid` AS `rowid`,`kalmut_registeredunit`.`cp2reffcode0` AS `cp2reffcode0`,`kalmut_registeredunit`.`regunit_unitid` AS `regunit_unitid`,`kalmut_unitpelayanan`.`namaunit` AS `namaunit`,`kalmut_unitpelayanan`.`status` AS `status`,`kalmut_unitpelayanan`.`flddisable` AS `flddisable` from (`kalmut_unitpelayanan` join `kalmut_registeredunit` on((`kalmut_unitpelayanan`.`kodeunit` = `kalmut_registeredunit`.`regunit_unitid`))) ;
