INSERT INTO `kalmut_katalogmutu` VALUES ('149', 'IKARS', '200', '200', null, null, 'Keterlambatan Asuhan Gizi Lanjutan ', null, null, null, '2', 'rate base', '(Jumlah Keterlambatan Asuhan Gizi Lanjutan  pada bulan tersebut/Jumlah Pemberian Asuhan Gizi Lanjutan  pada bulan tersebut.) x 100%', '1', 'Keterlambatan Asuhan Gizi Lanjutan ', null, '0', null, '0', '', null, null, '1');
INSERT INTO `kalmut_katalogmutu` VALUES ('150', 'IKARS', '201', '201', null, null, 'Kepatuhan Pemasangan Gelang Identitas pada Pasien IGD yang rawat inap', null, null, null, '2', 'rate base', '(Jumlah Pasien IGD yang rawat inap  telah dilakukan pemasangan gelang/Jumlah Pasien IGD yang rawat inap) x 100%', '1', 'Kepatuhan Pemasangan Gelang Identitas pada Pasien IGD yang rawat inap', null, '0', null, '0', '', null, null, '1');
INSERT INTO `kalmut_katalogmutu` VALUES ('151', 'IKARS', '202', '202', null, null, 'Ketepatan melakukan TBaK saat menerima instruksi verbal melalui telepon', null, null, null, '2', 'rate base', '(Numerator Ketepatan melakukan TBaK saat menerima instruksi verbal melalui telepon/Denominator Ketepatan melakukan TBaK saat menerima instruksi verbal melalui telepon) x 100%', '1', 'Ketepatan melakukan TBaK saat menerima instruksi verbal melalui telepon', null, '0', null, '0', '', null, null, '1');
INSERT INTO `kalmut_katalogmutu` VALUES ('152', 'IKARS', '203', '203', null, null, 'Kurangnya keamanan pengelolaan obat-obatab NORUM / LASA, elektrolit konsentrat, insulin, nutrisi parenteral, sedasi, heparin, agen radiokontras IV, dan agen kemoterapi. ', null, null, null, '2', 'rate base', '(Numerator Kurangnya keamanan pengelolaan obat-obatab NORUM / LASA, elektrolit konsentrat, insulin, nutrisi parenteral, sedasi, heparin, agen radiokontras IV, dan agen kemoterapi. /Denominator Kurangnya keamanan pengelolaan obat-obatab NORUM / LASA, elekt', '1', 'Kurangnya keamanan pengelolaan obat-obatab NORUM / LASA, elektrolit konsentrat, insulin, nutrisi parenteral, sedasi, heparin, agen radiokontras IV, dan agen kemoterapi. ', null, '0', null, '0', '', null, null, '1');
INSERT INTO `kalmut_katalogmutu` VALUES ('153', 'IKARS', '204', '204', null, null, 'Terjadinya pasien jatuh di lingkungan rumah sakit', null, null, null, '2', 'rate base', '(Numerator Terjadinya pasien jatuh di lingkungan rumah sakit/Denominator Terjadinya pasien jatuh di lingkungan rumah sakit) x 100%', '1', 'Terjadinya pasien jatuh di lingkungan rumah sakit', null, '0', null, '0', '', null, null, '1');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('1', '1', '1', '4e1789cc-6d29-11ec-a73f-1e544a7779f8', 'Ruang rawat inap ', 'Kelengkapan asesmen medis dalam waktu 24 jam setelah pasien masuk rawat inap', '', '', '', 'P', '', '', 'Yang dimaksud asesmen medis lengkap dalam waktu 24 jam setelah pasien masuk rawat inap adalah :\n<ol>\n	<li>proses kegiatan mengevaluasi pasien</li>\n	<li>oleh tenaga medis</li>\n	<li>paling lambat 24 jam setelah pasien masuk rawat inap</li>\n	<li>meliputi mengumpulkan informasi, menganalisa informasi dan membuat rencana pelayanan untuk memenuhi semua kebutuhan pasien yang telah diidentifikasi</li>\n</ol>\n', '', null, null, '2', 'Jumlah asesmen  lengkap yang dilakukan oleh tenaga medis dalam waktu 24 jam setelah pasien masuk  rawat inap dalam waktu 1 bulan', 'Jumlah total pasien yang masuk rawat inap dalam waktu 24 jam, dalam waktu 1 bulan', '2', null, '(Jumlah asesmen  lengkap yang dilakukan oleh tenaga medis dalam waktu 24 jam setelah pasien masuk  rawat inap dalam waktu 1 bulan/Jumlah total pasien yang masuk rawat inap dalam waktu 24 jam, dalam waktu 1 bulan) x 100%', '%', 'Rekam Medis', '100', '100', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('2', '2', '2', '4e178c92-6d29-11ec-a73f-1e544a7779f8', 'Instalasi rawat inap, Instalasi Pelayanan Intensif', 'Ketidakpatuhan pendokumentasian asesmen nyeri secara kontinyu di status pasien', '', '', '', 'P', '', '', 'Terjadinya ketidakpatuhan perawat dalam pendokumentasian asesmen nyeri secara kontinyu di status pasien baik asesmen awal maupun ulang', '', null, null, '2', 'Jumlah status pasien yang tidak ada dokumentasi  asesmen nyeri awal maupun ulang sesuai panduan manajemen nyeri per bulan', 'Jumlah seluruh  pasien dengan keluhan nyeri dalam bulan tersebut', '2', null, '(Jumlah status pasien yang tidak ada dokumentasi  asesmen nyeri awal maupun ulang sesuai panduan manajemen nyeri per bulan/Jumlah seluruh  pasien dengan keluhan nyeri dalam bulan tersebut) x 100%', '%', 'Rekam medis pasien', null, '5', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('3', '3', '3', '4e178d7e-6d29-11ec-a73f-1e544a7779f8', 'Instalasi laboratorium', 'Kerusakan sampel darah', '', '', 'I', '', '', '', 'Terjadinya lisis atau pembekuan darah yang tidak sesuai dengan syarat sampel darah yang baik', '', null, null, '2', 'Jumlah kerusakan sample darah per bulan', 'Jumlah sample darah pada bulan tersebut', '2', null, '(Jumlah kerusakan sample darah per bulan/Jumlah sample darah pada bulan tersebut) x 100%', '%', 'Catatan spesimen yang rusak', null, '0.5', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('4', '4', '4', '4e178fad-6d29-11ec-a73f-1e544a7779f8', 'Instalasi Laboratorium dan Instalasi Rawat Inap', 'Tidak terlaporkannya hasil kritis', '', '', 'I', '', '', '', 'Keterlambatan melaporkan / tidak terlaporkannya hasil kritis, yaitu hasil laborat yang nilainya menurut patofisiologi penyakit berpotensi mengancam jiwa penderita sehingga membutuhkan penanganan medis secepat mungkin.', '', null, null, '2', 'Jumlah jenis pemeriksaan dengan hasil kritis yang tidak terlaporkan per bulan', 'Jumlah jenis pemeriksaan dengan hasil kritis pada bulan tersebut', '2', null, '(Jumlah jenis pemeriksaan dengan hasil kritis yang tidak terlaporkan per bulan/Jumlah jenis pemeriksaan dengan hasil kritis pada bulan tersebut) x 100%', '%', 'Catatan pelaporan hasil kritis', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('5', '5', '5', '4e179050-6d29-11ec-a73f-1e544a7779f8', 'Instalasi rawat jalan, Instalasi rawat inap, ICU, IGD', 'Penolakan expertise', '', '', '', '', '', '', 'Kejadian&nbsp; yang menunjukkan banyaknya penolakan expertise oleh dokter pengirim', '', null, null, '2', 'Jumlah penolakan expertise per bulan', 'Jumlah seluruh pelayanan di radiologi pada bulan tersebut ', '2', null, '(Jumlah penolakan expertise per bulan/Jumlah seluruh pelayanan di radiologi pada bulan tersebut ) x 100%', '%', 'Laporan insiden ', null, '1', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('6', '6', '6', '4e1790e7-6d29-11ec-a73f-1e544a7779f8', 'Instalasi rawat jalan, IGD', 'Keterlambatan hasil foto rawat jalan', '', '', '', '', '', '', 'Angka yang menunjukkan  keterlambatan penerimaan hasil foto oleh pasien rawat jalan lebih dari tiga jam.jalan lebih dari tiga jam.', '', null, null, '2', 'Jumlah pasien rawat jalan yang menerima hasil foto beserta bacaan lebih dari 3 jam per bulan', 'Jumlah seluruh pasien rawat jalan yang dilakukan tindakan foto rontgen pada bulan tersebut ', '2', null, '(Jumlah pasien rawat jalan yang menerima hasil foto beserta bacaan lebih dari 3 jam per bulan/Jumlah seluruh pasien rawat jalan yang dilakukan tindakan foto rontgen pada bulan tersebut ) x 100%', '%', 'Catatan pelayanan radiologi', null, '3', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('7', '7', '7', '4e17927f-6d29-11ec-a73f-1e544a7779f8', 'Instalasi radiologi', 'Pemeriksaan ulang radiologi', '', '', '', 'P', '', '', 'Pemeriksaan ulang radiologiTerjadinya kesalahan pelaksanaan pemeriksaan radiologi', '', null, null, '2', 'Jumlah pemeriksaan ulang radiologi per bulan ', 'Jumlah pasien yang dilakukan pemeriksaan radiologi pada bulan tersebut', '2', null, '(Jumlah pemeriksaan ulang radiologi per bulan /Jumlah pasien yang dilakukan pemeriksaan radiologi pada bulan tersebut) x 100%', '%', 'Laporan insiden', null, '0.5', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('8', '8', '8', '4e179316-6d29-11ec-a73f-1e544a7779f8', 'Instalasi radiologi', 'Tidak dilakukannya asesmen awal radiologi', '', '', 'I', '', '', '', 'Asesmen awal radiologi adalah pemeriksaan pendahuluan yang dilakukan bagi semua pasien radiologi sebelum tindakan radiologi, serta didokumentasikan secara benar dan lengkap.', '', null, null, '2', 'Jumlah tindakan radiologi yang tidak dilakukan asesmen awal radiologi per bulan', 'Jumlah seluruh tindakan radiologi dalam bulan tersebut', '2', null, '(Jumlah tindakan radiologi yang tidak dilakukan asesmen awal radiologi per bulan/Jumlah seluruh tindakan radiologi dalam bulan tersebut) x 100%', '%', 'Rekam medis (Form asesmen awal radiologi)', null, '1', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('9', '9', '9', '4e1793a7-6d29-11ec-a73f-1e544a7779f8', 'Instalasi kamar operasi', 'Tidak dilakukannya&nbsp; penandaan lokasi operasi', '', '', 'I', '', '', '', 'Tidak dilakukannya penandaan lokasi operasi oleh operator', '', null, null, '2', 'Jumlah kejadian tidak dilakukannya penandaan lokasi operasi pada semua kasus operasi yang harus dilakukan penandaan lokasi operasi per bulan.', 'Jumlah semua kasus operasi yang harus dilakukan penandaan lokasi operasi dalam bulan tersebut.', '2', null, '(Jumlah kejadian tidak dilakukannya penandaan lokasi operasi pada semua kasus operasi yang harus dilakukan penandaan lokasi operasi per bulan./Jumlah semua kasus operasi yang harus dilakukan penandaan lokasi operasi dalam bulan tersebut.) x 100%', '%', 'Status rekam medis pasien', null, '2', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('10', '10', '10', '4e17953d-6d29-11ec-a73f-1e544a7779f8', 'Instalasi  rawat inap', 'Operasi ulang dengan diagnosa sama dan atau komplikasinya<br />\n&nbsp;', '', '', '', '', '', '', 'Dilakukannya operasi ulang (operasi dengan prosedur yang sama) dengan kasus / diagnosa yang sama dengan operasi sebelumnya dan / atau karena komplikasinya, dalam waktu 7 hari atau kurang.', '', null, null, '2', 'Jumlah operasi ulang dengan diagnosa sama / komplikasinya per bulan.', 'Jumlah seluruh operasi dalam bulan tersebut', '2', null, '(Jumlah operasi ulang dengan diagnosa sama / komplikasinya per bulan./Jumlah seluruh operasi dalam bulan tersebut) x 100%', '%', 'Status rekam medis pasien (laporan operasi)', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('11', '11', '11', '4e1795cc-6d29-11ec-a73f-1e544a7779f8', 'Instalasi kamar operasi', 'Kesalahan Prosedur Operasi', '', '', '', 'P', '', '', 'Terjadi insiden kesalahan prosedur operasi pada saat pasien dilakukan tindakan operasi', '', null, null, '2', 'Jumlah insiden salah prosedur operasi pada pasien', 'Jumlah insiden salah prosedur operasi dalam bulan tersebut', '2', null, '(Jumlah insiden salah prosedur operasi pada pasien/Jumlah insiden salah prosedur operasi dalam bulan tersebut) x 100%', '%', 'Laporan insiden', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('12', '12', '12', '4e17965c-6d29-11ec-a73f-1e544a7779f8', 'Instalasi Kamar  Operasi, Instalasi Rawat Inap', 'Kesalahan Lokasi Operasi', '', '', '', 'P', '', '', 'Terjadinya insiden kesalahan lokasi pada saat pasien dilakukan tindakan operasi', '', null, null, '2', 'Jumlah insiden kesalahan lokasi operasi pada pasien pembedahan', 'Jumlah insiden kesalahan lokasi operasi dalam bulan tersebut', '2', null, '(Jumlah insiden kesalahan lokasi operasi pada pasien pembedahan/Jumlah insiden kesalahan lokasi operasi dalam bulan tersebut) x 100%', '%', 'Laporan insiden', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('13', '13', '13', '4e1797de-6d29-11ec-a73f-1e544a7779f8', 'Instalasi Kamar  Operasi, Instalasi Rawat Inap', 'Kesalahan Diagnosa Pre dan post operasi', '', '', '', 'P', '', '', 'Terjadinya insiden kesalahan diagnosis pada pasien pra operasi, yang baru diketahui oleh operator pada saat durante operasi (diagnosis pra dan post operasi berbeda)', '', null, null, '2', 'Insiden kesalahan diagnosis pra operasi', 'Insiden kesalahan diagnosis pra operasi dalam bulan tersebut', '2', null, '(Insiden kesalahan diagnosis pra operasi/Insiden kesalahan diagnosis pra operasi dalam bulan tersebut) x 100%', '%', 'Laporan insiden', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('14', '14', '14', '4e17986c-6d29-11ec-a73f-1e544a7779f8', 'Instalasi Farmasi, Instalasi rawat inap, Instalasi rawat jalan, ICU, IGD, HD, Endoskopi', 'Kesalahan penyerahan perbekalan farmasi', '', '', '', 'P', '', '', 'Kesalahan&nbsp; penyerahan&nbsp;&nbsp; perbekalan&nbsp;&nbsp; farmasi (obat, alat kesehatan, dan sebagainya) dari Instalasi Farmasi ke ruang perawatan', '', null, null, '2', 'Jumlah kesalahan penyerahan perbekalan per bulan', 'Jumlah permintaan perbekalan dalam bentuk resep dan formulir permintaan pada bulan tersebut', '2', null, '(Jumlah kesalahan penyerahan perbekalan per bulan/Jumlah permintaan perbekalan dalam bentuk resep dan formulir permintaan pada bulan tersebut) x 100%', '%', 'Pelaporan insiden', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('15', '15', '15', '4e1799f7-6d29-11ec-a73f-1e544a7779f8', 'Instalasi Farmasi, instalasi rawat inap, Instalasi rawat jalan, IGD, ICU, HD, Endoskopi', 'Ketidaktepatan pemberian obat (5 benar)', '', '', '', 'P', '', '', 'Ketidaktepatan pemberian obat kepada pasien yang dinilai berdasarkan 5 benar, yaitu\n<ol>\n	<li>Benar pasien</li>\n	<li>Benar obat</li>\n	<li>Benar dosis</li>\n	<li>Benar waktu pemberian</li>\n	<li>Benar cara pemberian</li>\n</ol>\n', '', null, null, '2', 'Jumlah kesalahan / ketidaktepatan pemberian obat  (5 Benar)', 'Jumlah total kesalahan/ketidaktepatan pemberian obat dalam bulan tersebut', '2', null, '(Jumlah kesalahan / ketidaktepatan pemberian obat  (5 Benar)/Jumlah total kesalahan/ketidaktepatan pemberian obat dalam bulan tersebut) x 100%', '%', 'Laporan insiden', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('16', '16', '16', '4e179a87-6d29-11ec-a73f-1e544a7779f8', 'Instalasi kamar operasi', 'Ketidaklengkapan asesmen pre anestesi', '', '', 'I', '', '', '', 'Ketidaklengkapan asesmen pre anestesi&nbsp; meliputi : dokter anestesi&nbsp; tidak visite pada saat pasien masih di ruang perawatan (pemeriksaan fisik, pemeriksaan penunjang, KIE / Informed Consent), dan rekam medis tidak terisi secara lengkap sebelum pasien dilakukan anestesi.', '', null, null, '2', 'Jumlah pasien yang tidak dilakukan asesmen pre anestesi secara lengkap per bulan', 'Jumlah pasien operasi dengan anestesi dalam bulan tersebut', '2', null, '(Jumlah pasien yang tidak dilakukan asesmen pre anestesi secara lengkap per bulan/Jumlah pasien operasi dengan anestesi dalam bulan tersebut) x 100%', '%', 'Status rekam medis pasien', null, '1', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('17', '17', '17', '4e179c10-6d29-11ec-a73f-1e544a7779f8', 'Instalasi rawat inap', 'Kejadian Reaksi Transfusi', '', '', '', 'P', '', '', 'Yang dimaksud kejadian reaksi transfusi adalah reaksi yang timbul akibat dilakukannya transfusi darah yang tidak sesuai dengan golongan darah pasien. (Reaksi incompatibilitas)', '', null, null, '2', 'Jumlah kasus reaksi  transfusi darah per hari', 'Jumlah total kasus pemasangan transfusi darah (kantong darah) di hari tersebut', '2', null, '(Jumlah kasus reaksi  transfusi darah per hari/Jumlah total kasus pemasangan transfusi darah (kantong darah) di hari tersebut) x 100%', '%', 'Status rekam medis pasien, laporan insiden', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('18', '18', '18', '4e179cf5-6d29-11ec-a73f-1e544a7779f8', 'Instalasi rekam medis', 'Ketidaklengkapan informed consent', '', '', 'I', '', '', '', 'Informed Concent adalah persetujuan tindakan kedokteran yang diberikan oleh pasien/keluarga terdekatnya setelah mendapatkan penjelasan secara lengkap mengenai tindakan kedokteran yang akan dilakukan terhadap pasien tersebut serta risiko yang akan terjadi terhadap pasien.<br />\nKetidaklengkapan informed consent adalah tidak terisinya form informed consent secara lengkap, data maupun tanda tangan, baik pada lembar informasi maupun pada lembar consent.<br />\n&nbsp;', '', null, null, '2', 'Informed consent yang tidak lengkap per bulan', 'Jumlah tindakan kedokteran dari seluruh pasien dalam bulan tersebut', '2', null, '(Informed consent yang tidak lengkap per bulan/Jumlah tindakan kedokteran dari seluruh pasien dalam bulan tersebut) x 100%', '%', 'Rekam medis pasien', null, '1', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('19', '19', '19', '4e179e81-6d29-11ec-a73f-1e544a7779f8', 'Instalasi rekam medis', 'Ketidaklengkapan catatan medis pasien (KLPCM)', '', '', '', '', '', '', 'Ketidaklengkapan pengisian catatan medis yang berisi seluruh informasi tentang pasien sesuai dengan formulir yang disediakan, khususnya resume medis dan resume keperawatan termasuk seluruh hasil pemeriksaan penunjang, dalam waktu 14 hari setelah pasien keluar dari Rumah Sakit', '', null, null, '2', 'Jumlah catatan rekam medis yang belum lengkap dan benar dalam 14 hari per bulan', 'Jumlah catatan rekam medis dalam bulan tersebut', '2', null, '(Jumlah catatan rekam medis yang belum lengkap dan benar dalam 14 hari per bulan/Jumlah catatan rekam medis dalam bulan tersebut) x 100%', '%', 'Rekam medis pasien', null, '1', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('20', '20', '20', '4e179f15-6d29-11ec-a73f-1e544a7779f8', 'Intalasi rawat inap, ICU, Instalasi Rawat Jalan', 'Infeksi Daerah&nbsp; Operasi (IDO)', '', '', '', 'P', '', '', 'Infeksi pasca operasi adalah adanya infeksi rumah sakit (HAIs) pada semua kategori luka sayatan operasi yang dilaksanakan di rumah sakit dan ditandai oleh rasa panas (kalor), nyeri (dolor), kemerahan (rubor), bengkak (tumor) gangguan fungsi (fungsiolesa) dan keluarnya nanah (pus) yang muncul dalam waktu lebih 3 x 24 jam sampai dengan 30 hari pasca operasi, atau sampai dengan 1 tahun jika terdapat implant', '', null, null, '2', 'Jumlah pasien yang mengalami infeksi pasca operasi dalam satu bulan', 'Jumlah seluruh pasien yang dioperasi di rumah sakit dalam bulan tersebut', '2', null, '(Jumlah pasien yang mengalami infeksi pasca operasi dalam satu bulan/Jumlah seluruh pasien yang dioperasi di rumah sakit dalam bulan tersebut) x 100%', '%', 'Rekam medis pasien', null, '2', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('21', '21', '21', '4e17a09d-6d29-11ec-a73f-1e544a7779f8', 'Intalasi rawat inap, ICU', 'Sepsis', '', '', '', 'P', '', '', 'Sepsis yang terjadi setelah pasien dirawat di rumah sakit', '', null, null, '2', 'Jumlah pasien sepsis per bulan', 'Jumlah pasien rawat inap pada  bulan tersebut', '2', null, '(Jumlah pasien sepsis per bulan/Jumlah pasien rawat inap pada  bulan tersebut) x 100%', '%', 'Rekam medis pasien', null, '1', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('22', '22', '22', '4e17a135-6d29-11ec-a73f-1e544a7779f8', 'Intalasi rawat inap, ICU', 'Infeksi Luka Infus (ILI / Plebitis)', '', '', '', 'P', '', '', 'Keadaan infeksi yang terjadi disekitar tusukan atau bekas tusukan jarum infus di pembuluh darah perifer dan timbul minimal 48 jam setelah pemasangan (sesuai pedoman surveilans infeksi Kemenkes RI tahun 2011).', '', null, null, '2', 'Jumlah kasus infeksi luka infus per bulan', 'Jumlah hari pemasangan infus dalam bulan tersebut', '2', null, '(Jumlah kasus infeksi luka infus per bulan/Jumlah hari pemasangan infus dalam bulan tersebut) x 1&permil;', '&permil;', 'Rekam medis pasien', null, '20', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('23', '23', '23', '4e17a2fa-6d29-11ec-a73f-1e544a7779f8', 'Intalasi rawat inap, ICU', 'Infeksi Aliran Darah Primer&nbsp; (IADP)', '', '', '', 'P', '', '', 'Keadaan infeksi yang terjadi akibat masuknya mikroba melalui peralatan yang dimasukkan langsung ke sistem pembuluh darah melalui insersi intravena kateter, baik berupa kateter vena maupun arteri dalam rangka perawatan maupun diagnostik (CVC / Central Venous Catheter, vena perifer / infus, double lumen untuk hemodialisa) infeksi timbul minimal 3 kali 24 jam&nbsp; (72 jam) setelah pemasangan.', '', null, null, '2', 'Jumlah kasus infeksi aliran darah primer karena pemasangan intravaskular kateter  perbulan', 'Jumlah hari pemasangan intravaskular kateter dalam bulan tersebut', '2', null, '(Jumlah kasus infeksi aliran darah primer karena pemasangan intravaskular kateter  perbulan/Jumlah hari pemasangan intravaskular kateter dalam bulan tersebut) x 1&permil;', '&permil;', 'Rekam medis pasien', null, '10', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('24', '24', '24', '4e17a48e-6d29-11ec-a73f-1e544a7779f8', 'Intalasi rawat inap, Instalasi Pelayanan Intensif', 'Infeksi Saluran Kemih (ISK)', '', '', '', 'P', '', '', 'Keadaan&nbsp; infeksi&nbsp; yang&nbsp; terjadi&nbsp; disekitar&nbsp; uretra atau selang kateter dan timbul setelah 3 kali 24 jam dilakukan pemasangan kateter di rumah sakit.', '', null, null, '2', 'Jumlah kasus infeksi karena pemasangan kateter per bulan', 'Jumlah hari pemasangan kateter dalam bulan tersebut', '2', null, '(Jumlah kasus infeksi karena pemasangan kateter per bulan/Jumlah hari pemasangan kateter dalam bulan tersebut) x 1&permil;', '&permil;', 'Rekam medis pasien', null, '10', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('25', '25', '25', '4e17a61d-6d29-11ec-a73f-1e544a7779f8', 'Instalasi Pelayanan Intensif', 'Pneumonia akibat pemakaian ventilator (Ventilator Associated Pneumonia /VAP)', '', '', '', 'P', '', '', 'Ventilator Associated Pneumonia (VAP) adalah pneumonia yang terjadi akibat pemasangan ventilator di rumah sakit.', '', null, null, '2', 'Jumlah VAP  atau pneumonia yang terjadi akibat pemasangan ventilator per bulan', 'Jumlah hari pemakaian Endotracheal Tube (ETT) pada bulan tersebut', '2', null, '(Jumlah VAP  atau pneumonia yang terjadi akibat pemasangan ventilator per bulan/Jumlah hari pemakaian Endotracheal Tube (ETT) pada bulan tersebut) x 1&permil;', '&permil;', 'Rekam medis pasien', null, '20', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('26', '26', '26', '4e17a7ca-6d29-11ec-a73f-1e544a7779f8', 'Instalasi Rawat Inap dan Instalasi Pelayanan Intensif, Unit stroke', 'Kejadian dekubitus selama masa perawatan<br />\n&nbsp;', '', '', '', 'P', '', '', 'Kerusakan/kematian kulit sampai jaringan dibawah kulit, bahkan menembus otot sampai mengenai tulang akibat adanya penekanan pada suatu area secaraterus menerus sehingga mengakibatkan gangguan sirkulasi darah setempat, yang timbul minimal 3 x 24 jam setelah rawat inap', '', null, null, '2', 'Jumlah kasus luka dekubitus per bulan', 'Jumlah pasien tirah baring pada bulan tersebut', '2', null, '(Jumlah kasus luka dekubitus per bulan/Jumlah pasien tirah baring pada bulan tersebut) x 100%', '%', 'Rekam medis pasien', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('27', '27', '27', '4e17a963-6d29-11ec-a73f-1e544a7779f8', 'Semua unit ', 'Ketidaktepatan identifikasi pasien', '', '', '', 'P', '', '', 'Ketidaktepatan identifikasi adalah kesalahan penentuan identitas pasien sejak awal pasien masuk sampai dengan pasien keluar,terhadap semua pelayanan yang diterima oleh pasien', '', null, null, '2', 'Jumlah insiden ketidaktepatan identifikasi pasien', 'Jumlah total insiden ketidaktepatan identifikasi pasien dalam bulan tersebut', '2', null, '(Jumlah insiden ketidaktepatan identifikasi pasien/Jumlah total insiden ketidaktepatan identifikasi pasien dalam bulan tersebut) x 100%', '%', 'Laporan insiden', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('28', '28', '28', '4e17ab02-6d29-11ec-a73f-1e544a7779f8', 'Semua unit pelayanan', 'Insiden keamanan obat yang perlu diwaspadai', '', '', '', 'P', '', '', 'Obat yang perlu diwaspadai (High allert ) adalah obat yang memiliki risiko lebih tinggi untuk menyebabkan&nbsp; / menimbulkan adanya komplikasi atau membahayakan pasien secara signifikan jika terdapat kesalahan penggunaan dan penyimpanan.', '', null, null, '2', 'Insiden kejadian/kesalahan yang terkait dengan keamanan obat-obatan yang perlu diwaspadai', 'Jumlah total insiden/kejadian kesalahan yang terkait dengan keamanan obat-obatan yang perlu diwaspadai dalam bulan tersebut', '2', null, '(Insiden kejadian/kesalahan yang terkait dengan keamanan obat-obatan yang perlu diwaspadai/Jumlah total insiden/kejadian kesalahan yang terkait dengan keamanan obat-obatan yang perlu diwaspadai dalam bulan tersebut) x 100%', '%', 'Laporan insiden', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('29', '29', '29', '4e17abab-6d29-11ec-a73f-1e544a7779f8', 'Seluruh area Rumah sakit ', 'Kejadian pasien jatuh', '', '', '', 'P', '', '', 'Pasien jatuh di lingkungan rumah sakit oleh sebab apapun', '', null, null, '2', 'Jumlah insiden pasien jatuh dalam bulan tersebut', 'Jumlah total insiden pasien jatuh dalam bulan tersebut', '2', null, '(Jumlah insiden pasien jatuh dalam bulan tersebut/Jumlah total insiden pasien jatuh dalam bulan tersebut) x 100%', '%', 'Laporan insiden', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('30', '30', '30', '4e17ac44-6d29-11ec-a73f-1e544a7779f8', 'Unit Stroke, Instalasi Rawat Inap dan Instalasi Pelayanan Intensif', 'Pasien stroke ischemic yang tidak mendapatkan terapi anti trombotik pada saat KRS.', '', '', '', 'P', '', '', '<ul>\n	<li>Pemberian obat anti trombotik kepada pasien stroke ischemic</li>\n	<li>Preparat anti trombotik yang berisi: asam asetil salisilat, clopidogrel</li>\n	<li>Diisi oleh unit yang memulangkan pasien</li>\n</ul>\n', '', null, null, '2', 'Jumlah pasien stroke ischemic yang tidak mendapatkan terapi anti trombotik pada saat KRS perbulan ', 'Jumlah seluruh pasien stroke ischemic yang KRS dalam bulan tersebut', '2', null, '(Jumlah pasien stroke ischemic yang tidak mendapatkan terapi anti trombotik pada saat KRS perbulan /Jumlah seluruh pasien stroke ischemic yang KRS dalam bulan tersebut) x 100%', '%', 'Rekam medis', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('31', '31', '31', '4e17ae23-6d29-11ec-a73f-1e544a7779f8', 'Unit Stroke, Instalasi Rawat Inap dan Instalasi Pelayanan Intensif', 'Pasien stroke yang tidak mendapatkan edukasi selama masa perawatan di rumah sakit', '', '', '', 'P', '', '', '<ul>\n	<li>Edukasi pasien stroke adalah pemberian informasi dan pendidikan seputar stroke terhadap pasien dan / atau keluarga yang dilakukan oleh dokter penanggung jawab / perawat / fisioterapis / ahli gizi / apoteker atau tenaga kesehatan lainnya.</li>\n	<li>Diisi oleh unit yang pertama kali menerima&nbsp; pasien</li>\n</ul>\n', '', null, null, '2', 'Jumlah pasien stroke yang tidak mendapatkan edukasi tentang stroke selama menjalani rawat inap selama satu bulan', 'Jumlah seluruh pasien stroke yang dirawat inap dalam bulan tersebut', '2', null, '(Jumlah pasien stroke yang tidak mendapatkan edukasi tentang stroke selama menjalani rawat inap selama satu bulan/Jumlah seluruh pasien stroke yang dirawat inap dalam bulan tersebut) x 100%', '%', 'Rekam medis', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('32', '32', '32', '4e17aebe-6d29-11ec-a73f-1e544a7779f8', 'Instalasi Rawat Inap dan Instalasi Pelayanan Intensif', 'Pasien IMA yang tidak mendapatkan terapi aspirin (anti trombotik) dalam waktu 24 jam sejak datang ke Rumah Sakit.', '', '', '', 'P', '', '', '<ul>\n	<li>Pemberian terapi aspirin kepada pasien Infark Miokard Akut dalam waktu 24 jam sebelum atau sesudah tiba di rumah sakit .</li>\n	<li>Preparat anti trombotik yang berisi: asetil salisilat, clopidogrel</li>\n</ul>\n', '', null, null, '2', 'Jumlah pasien IMA yang tidak  mendapatkan terapi aspirin/anti trombotik  dalam waktu 24 jam sejak datang ke RS per bulan ', 'Jumlah seluruh pasien IMA dalam bulan tersebut', '2', null, '(Jumlah pasien IMA yang tidak  mendapatkan terapi aspirin/anti trombotik  dalam waktu 24 jam sejak datang ke RS per bulan /Jumlah seluruh pasien IMA dalam bulan tersebut) x 100%', '%', 'Rekam medis', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('33', '33', '33', '4e17af49-6d29-11ec-a73f-1e544a7779f8', 'Unit perinatologi', 'Bayi baru lahir yang tidak mendapatkan ASI Eksklusif selama rawat inap', '', '', '', 'P', '', '', 'Pemberian Air Susu Ibu saja kepada bayi umur 0 &ndash; 6 bulan tanpa diberikan makanan atau minuman tambahan selain obat untuk terapi (pengobatan penyakit) selama masa rawat inap', '', null, null, '2', 'Jumlah bayi baru lahir yang tidak mendapat ASI eksklusif selama masa rawat inap dalam satu bulan', 'Jumlah seluruh bayi baru lahir dalam bulan tersebut', '2', null, '(Jumlah bayi baru lahir yang tidak mendapat ASI eksklusif selama masa rawat inap dalam satu bulan/Jumlah seluruh bayi baru lahir dalam bulan tersebut) x 100%', '%', 'Rekam medis', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('34', '34', '34', '4e17b0ef-6d29-11ec-a73f-1e544a7779f8', 'Instalasi Rawat Inap dan Instalasi Pelayanan Intensif', 'Pasien asma anak yang tidak menerima bronkodilator selama masa rawat inap', '', '', '', 'P', '', '', 'Pemberian obat brokodilator pada pasien asma anak (&lt; 15 tahun) selama masa rawat inap', '', null, null, '2', 'Jumlah pasien asma anak yang  tidak menerima bronkodilator selama masa rawat inap per bulan', 'Jumlah seluruh pasien asma anak dalam bulan tersebut', '2', null, '(Jumlah pasien asma anak yang  tidak menerima bronkodilator selama masa rawat inap per bulan/Jumlah seluruh pasien asma anak dalam bulan tersebut) x 100%', '%', 'Rekam medis', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('35', '35', '35', '4e17b181-6d29-11ec-a73f-1e544a7779f8', 'Poli DOTS', 'Penanganan pasien tuberkulosis yang tidak sesuai strategi DOTS (Directly Observed Treatment Shortcourse)', '', '', '', 'P', '', '', 'Pelayanan tuberkulosis dengan strategi DOTS adalah pelayanan tuberkulosis dengan 5 (lima) strategi penanggulangan tuberkulosis nasional.<br />\nPenegakan diagnosis dan follow up pengobatan pasien tuberkulosis harus melalui pemeriksaan mikroskopis tuberkulosis, pengobatan harus menggunakan paduan obat anti tuberkulosis yang sesuai dengan standar penanggulangan tuberkulosis nasional, dan semua pasien yang tuberkulosis yang diobati dievaluasi secara kohort sesuai dengan penanggulangan tuberkulosis nasional', '', null, null, '2', 'Jumlah semua pasien tuberkulosis yang tidak ditangani sesuai dengan strategi DOTS per bulan', 'Jumlah seluruh pasien tuberculosis yang ditangani dalam bulan tersebut.', '2', null, '(Jumlah semua pasien tuberkulosis yang tidak ditangani sesuai dengan strategi DOTS per bulan/Jumlah seluruh pasien tuberculosis yang ditangani dalam bulan tersebut.) x 100%', '%', 'Rekam Medis', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('36', '36', '36', '4e17b285-6d29-11ec-a73f-1e544a7779f8', 'Laboratorium, Poli DOTS', 'Proporsi pasien TB paru terkonfirmasi bakteriologis diantara terduga TB', '', '', 'I', 'P', '', '', 'Terduga TB : adalah semua pasien yang&nbsp; diduga menderita tuberkulosis<br />\nTerkonfirmasi bakteriologis : minimal 1 (satu) dari 3 (tiga) spesimen pemeriksaan dahak adalah BTA(+', '', null, null, '2', 'Jumlah seluruh pasien terdiagnosa TB terkonfirmasi bakteriologis pada triwulan tersebut.', 'Jumlah seluruh pasien terduga TB yang melakukan pemeriksaan dahak mikroskopis pada bulan tersebut.', '2', null, '(Jumlah seluruh pasien terdiagnosa TB terkonfirmasi bakteriologis pada triwulan tersebut./Jumlah seluruh pasien terduga TB yang melakukan pemeriksaan dahak mikroskopis pada bulan tersebut.) x 100%', '%', 'TB 04, TB 06', null, '5-15', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('37', '37', '37', '4e17b448-6d29-11ec-a73f-1e544a7779f8', 'Poli DOTS', 'Angka konversi', '', '', '', 'P', '', '', 'Angka konversi adalah prosentase pasien TB paru terkonfirmasi bakteriologis yang mengawali perubahan menjadi BTA negatif setelah menjalani masa pengobatan tahap awal&nbsp; diantara pasien TB paru terkonfirmasi bakteriologis yang diobati.', '', null, null, '2', 'Jumlah seluruh pasien  TB paru terkonfirmasi bakteriologis dengan hasil pemeriksaan BTA akhir tahap awal negatif', 'Jumlah seluruh  pasien TB paru terkonfirmasi bakteriologis yang diobati.', '2', null, '(Jumlah seluruh pasien  TB paru terkonfirmasi bakteriologis dengan hasil pemeriksaan BTA akhir tahap awal negatif/Jumlah seluruh  pasien TB paru terkonfirmasi bakteriologis yang diobati.) x 100%', '%', 'TB 03, TB 04', null, '80', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('38', '38', '38', '4e17b4d4-6d29-11ec-a73f-1e544a7779f8', 'Poli DOTS', 'Angka kesembuhan', '', '', '', 'P', '', '', 'Angka kesembuhan adalah angka yang menunjukkan prosentase pasien TB paru terkonfirmasi bakteriologis yang sembuh setelah selesai masa pengobatan diantara pasien TB paru terkonfirmasi bakteriologis&nbsp; yang tercatat.', '', null, null, '2', 'Jumlah seluruh pasien TB paru terkonfirmasi bakteriologis yang sembuh.', 'Jumlah seluruh  pasien TB paru terkonfirmasi bakteriologis yang diobati', '2', null, '(Jumlah seluruh pasien TB paru terkonfirmasi bakteriologis yang sembuh./Jumlah seluruh  pasien TB paru terkonfirmasi bakteriologis yang diobati) x 100%', '%', 'TB 01 dan TB 03', null, '85', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('39', '39', '39', '4e17b55b-6d29-11ec-a73f-1e544a7779f8', 'Unit Kamar bersalin', 'Kematian ibu melahirkan karena eklampsi', '', '', '', '', '', '', 'Insiden yang menunjukkan banyaknya ibu yang meninggal karena eklampsia<br />\nEklampsia adalah suatu kelainan akut yang terjadi pada wanita hamil, bersalin, atau nifas yang ditandai dengan pre-eklampsia serta timbulnya kejang-kejang atau komplikasi lainnya, yang bukan disebabkan karena kelainan neurologi', '', null, null, '2', 'Jumlah ibu meninggal karena eklampsia per bulan', 'Jumlah ibu dengan eklampsia pada bulan tersebut', '2', null, '(Jumlah ibu meninggal karena eklampsia per bulan/Jumlah ibu dengan eklampsia pada bulan tersebut) x 100%', '%', 'Rekam medis pasien', null, '0.5', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('40', '40', '40', '4e17b704-6d29-11ec-a73f-1e544a7779f8', 'Unit Kamar bersalin', 'Kematian ibu melahirkan karena perdarahan', '', '', '', '', '', '', 'Insiden yang menunjukkan banyaknya ibu yang meninggal karena perdarahan yang dapat terjadi pada semua kala dalam persalinan', '', null, null, '2', 'Jumlah ibu melahirkan yang meninggal karena perdarahan perbulan', 'Jumlah ibu melahirkan dengan perdarahan pada bulan tersebut', '2', null, '(Jumlah ibu melahirkan yang meninggal karena perdarahan perbulan/Jumlah ibu melahirkan dengan perdarahan pada bulan tersebut) x 100%', '%', 'Rekam medis pasien', null, '0.5', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('41', '41', '41', '4e17b79c-6d29-11ec-a73f-1e544a7779f8', 'Unit Kamar bersalin', 'Ketidakmampuan menangani BBLR 1500-2500gr', '', '', '', '', '', '', 'BBLR adalah bayi yang lahir dengan berat badan 1500 &ndash; 2500 gr', '', null, null, '2', 'Jumlah BBLR 1500 – 2500 gr dengan usia kehamilan &ge; 32 minggu  yang tidak berhasil ditangani  per bulan', 'Jumlah seluruh BBLR 1500 – 2500 gr dengan usia kehamilan &ge; 32 minggu yang ditangani dalam bulan tersebut', '2', null, '(Jumlah BBLR 1500 – 2500 gr dengan usia kehamilan &ge; 32 minggu  yang tidak berhasil ditangani  per bulan/Jumlah seluruh BBLR 1500 – 2500 gr dengan usia kehamilan &ge; 32 minggu yang ditangani dalam bulan tersebut) x 100%', '%', 'Rekam medis pasien', null, '0.5', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('42', '42', '42', '4e17b93b-6d29-11ec-a73f-1e544a7779f8', 'Unit Kamar Bersalin', 'Keterlambatan operasi sectio caesarea', '', '', '', '', '', '', 'Sectio caesarea adalah suatu tindakan pembedahan untuk mengeluarkan janin dari perut ibu.<br />\nKeterlambatan SC adalah penundaan pelaksanaan SC &gt; 30 menit dari waktu yang telah dijadwalkan', '', null, null, '2', 'Jumlah ibu yang mengalami keterlambatan sectio caesarea pada bulan tersebut', 'Jumlah ibu yang mengalami sectio caesarea pada bulan tersebut', '2', null, '(Jumlah ibu yang mengalami keterlambatan sectio caesarea pada bulan tersebut/Jumlah ibu yang mengalami sectio caesarea pada bulan tersebut) x 100%', '%', 'Rekam medis pasien', null, '0.5', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('43', '43', '43', '4e17b9e6-6d29-11ec-a73f-1e544a7779f8', 'Unit Kamar Bersalin', 'Keterlambatan penyediaan darah', '', '', '', '', '', '', 'Adalah keterlambatan waktu menyediakan labu darah sesuai pesanan &gt; 60 menit terhitung mulai form permintaan darah diterima oleh petugas Bank darah rumah sakit sampai dengan labu darah diterima oleh perawat ruangan.', '', null, null, '2', 'Jumlah ibu hamil / bersalin / nifas yang mengalami keterlambatan penyediaan darah pada bulan tersebut', 'Jumlah ibu hamil / bersalin / nifas yang membutuhkan transfusi darah pada bulan tersebut.', '2', null, '(Jumlah ibu hamil / bersalin / nifas yang mengalami keterlambatan penyediaan darah pada bulan tersebut/Jumlah ibu hamil / bersalin / nifas yang membutuhkan transfusi darah pada bulan tersebut.) x 100%', '%', 'Rekam medis pasien', null, '0.5', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('44', '44', '44', '4e17ba70-6d29-11ec-a73f-1e544a7779f8', 'Unit Kamar Bersalin', 'Kejadian tidak dilakukan Inisiasi Menyusu Dini (IMD) pada bayi baru lahir', '', '', '', 'P', '', '', 'Inisiasi Menyusu Dini adalah bayi baru lahir diberi kesempatan untuk memulai atau inisiasi menyusu sendiri segera setelah lahir&nbsp; dengan membiarkan kontak kulit bayi dan ibu setidaknya satu jam atau sampai menyusu pertama selesai.', '', null, null, '2', 'Jumlah bayi baru lahir yang tidak dilakukan IMD pada bulan tersebut', 'Jumlah seluruh bayi baru lahir yang dapat dilakukan IMD pada bulan tersebut', '2', null, '(Jumlah bayi baru lahir yang tidak dilakukan IMD pada bulan tersebut/Jumlah seluruh bayi baru lahir yang dapat dilakukan IMD pada bulan tersebut) x 100%', '%', 'Rekam medis pasien', null, '0.5', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('45', '45', '45', '4e17bc18-6d29-11ec-a73f-1e544a7779f8', 'Instalasi rawat inap', 'Angka perawatan ulang', '', '', '', '', '', '', 'Jumlah pasien rawat inap ulang dengan penyakit yang sama dalam kurun waktu kurang dari tujuh hari setelah pasien pulang dari rumah sakit', '', null, null, '2', 'Jumlah pasien rawat ulang per bulan tersebut', 'Jumlah pasien masuk rumah sakit dalam  bulan tersebut', '2', null, '(Jumlah pasien rawat ulang per bulan tersebut/Jumlah pasien masuk rumah sakit dalam  bulan tersebut) x 100%', '%', 'Status rekam medis', null, '0.5', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('46', '46', '46', '4e17bca2-6d29-11ec-a73f-1e544a7779f8', 'Instalasi Pelayanan Intensif', 'Pasien yang kembali ke Instalasi Pelayanan Intensif (ICU) dengan kasus yang sama &lt; 72 jam', '', '', '', '', '', '', 'Pasien kembali ke pelayanan intensif dari ruang rawat inap dengan kasus yang sama dalam waktu &lt; 72 jam', '', null, null, '2', 'Jumlah pasien yang kembali ke Instalasi Pelayanan Intensif dengan kasus yang sama dalam waktu &lt; 72 jam pada per bulan', 'Jumlah seluruh  pasien yang dirawat di Instalasi Pelayanan Intensif dalam bulan tersebut', '2', null, '(Jumlah pasien yang kembali ke Instalasi Pelayanan Intensif dengan kasus yang sama dalam waktu &lt; 72 jam pada per bulan/Jumlah seluruh  pasien yang dirawat di Instalasi Pelayanan Intensif dalam bulan tersebut) x 100%', '%', 'Status rekam medis pasien', null, '2', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('47', '47', '47', '4e17be4b-6d29-11ec-a73f-1e544a7779f8', 'Instalasi rawat inap, instalasi pelayanan intensif', 'Kejadian pulang atas permintaan sendiri', '', '', '', '', '', '', 'Pulang atas permintaan sendiri adalah pulang atas permintaan pasien atau keluarga pasien sebelum diputuskan pulang oleh dokter', '', null, null, '2', 'Jumlah pasien pulang atas permintaan sendiri  per bulan ', 'Jumlah seluruh pasien yang dirawat dalam bulan tersebut', '2', null, '(Jumlah pasien pulang atas permintaan sendiri  per bulan /Jumlah seluruh pasien yang dirawat dalam bulan tersebut) x 100%', '%', 'Status rekam medis pasien', null, '1', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('48', '48', '48', '4e17bed7-6d29-11ec-a73f-1e544a7779f8', 'Proses Instalasi rehabilitasi medis', 'Kesalahan tindakan rehabilitasi medis', '', '', '', 'P', '', '', 'Kesalahan tindakan rehabilitasi medis adalah memberikan atau tidak memberikan tindakan rehabilitasi medis yang diperlukan yang tidak sesuai dengan rencana asuhan dan/atau tidak sesuai dengan pedoman standar pelayanan rehabilitasi medis', '', null, null, '2', 'Jumlah pasien yang mengalami kesalahan tindakan rehabilitasi medis per bulan ', 'Jumlah seluruh pasien yang diprogram rehabilitasi medis dalam bulan tersebut', '2', null, '(Jumlah pasien yang mengalami kesalahan tindakan rehabilitasi medis per bulan /Jumlah seluruh pasien yang diprogram rehabilitasi medis dalam bulan tersebut) x 100%', '%', 'Rekam medis pasien', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('49', '49', '49', '4e17c099-6d29-11ec-a73f-1e544a7779f8', 'Instalasi Rekam Medis', 'Ketidaklengkapan pengisian resume medis rawat jalan', '', '', '', 'P', '', '', 'Resume rawat jalan adalah ringkasan pengobatan pasien rawat jalan yang terdiri dari diagnosa medis, riwayat alergi, pengobatan terakhir, prosedur bedah, dan riwayat perawatan', '', null, null, '2', 'Jumlah resume rawat jalan yang tidak terisi dengan lengkap per bulan ', 'Jumlah kunjungan yang membutuhkan resume rawat jalan dalam bulan tersebut.', '2', null, '(Jumlah resume rawat jalan yang tidak terisi dengan lengkap per bulan /Jumlah kunjungan yang membutuhkan resume rawat jalan dalam bulan tersebut.) x 100%', '%', 'Rekam medis pasien', null, '1', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('50', '50', '50', '4e17c249-6d29-11ec-a73f-1e544a7779f8', 'Instalasi rawat inap, Instalasi Pelayanan Intensif', 'Sisa makan siang pasien non diit', '', '', '', '', '', '', 'Porsi makan siang yang tidak habis dimakan oleh pasien non diit &ge; &frac12; porsi makan yang disediakan.', '', null, null, '2', 'Jumlah pasien non diit yang tidak menghabiskan makan siangnya &ge; &frac12; porsi  per bulan ', 'Jumlah pasien non diit rawat inap yang makan siang dalam bulan tersebut', '2', null, '(Jumlah pasien non diit yang tidak menghabiskan makan siangnya &ge; &frac12; porsi  per bulan /Jumlah pasien non diit rawat inap yang makan siang dalam bulan tersebut) x 100%', '%', 'Catatan petugas pantry ruang rawat inap', null, '5', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('51', '51', '51', '4e17c2d9-6d29-11ec-a73f-1e544a7779f8', 'Instalasi rawat inap, Instalasi Pelayanan Intensif', 'Kesalahan diit pasien', '', '', '', 'P', '', '', 'Kesesuaian jenis diit antara yang diminta oleh dokter dengan yang disajikan pada saat makan.<br />\nKesesuaian diit meliputi jumlah kalori, jenis makanan, volume diit cair.', '', null, null, '2', 'Jumlah kejadian kesalahan jenis diit makanan pasien per bulan ', 'Jumlah porsi makanan diit dalam bulan tersebut', '2', null, '(Jumlah kejadian kesalahan jenis diit makanan pasien per bulan /Jumlah porsi makanan diit dalam bulan tersebut) x 100%', '%', 'Catatan petugas pantry ruangan', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('52', '52', '52', '4e17c477-6d29-11ec-a73f-1e544a7779f8', 'Instalasi kamar operasi', 'Ketidaklengkapan Laporan Operasi', '', '', '', 'P', '', '', 'Ketidaklengkapan penulisan laporan operasi setelah pasien keluar dari kamar operasi', '', null, null, '2', 'Jumlah  ketidaklengkapan laporan operasi per bulan ', 'Jumlah pasien operasi pada bulan tersebut (sesuai data dari IKO)', '2', null, '(Jumlah  ketidaklengkapan laporan operasi per bulan /Jumlah pasien operasi pada bulan tersebut (sesuai data dari IKO)) x 100%', '%', 'Status rekam medis pasien', null, '1', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('53', '53', '53', '4e17c501-6d29-11ec-a73f-1e544a7779f8', 'Instalasi kamar operasi', 'Ketidaklengkapan Laporan Anestesi', '', '', '', 'P', '', '', 'Ketidaklengkapan penulisan laporan anestesi setelah pasien keluar dari kamar operasi', '', null, null, '2', 'Jumlah  ketidaklengkapan laporan anestesi per bulan ', 'Jumlah total pasien operasi dengan anestesi pada bulan tersebut (sesuai data dari IKO)', '2', null, '(Jumlah  ketidaklengkapan laporan anestesi per bulan /Jumlah total pasien operasi dengan anestesi pada bulan tersebut (sesuai data dari IKO)) x 100%', '%', 'Status rekam medis  pasien', null, '1', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('54', '54', '54', '4e17c6a7-6d29-11ec-a73f-1e544a7779f8', 'Instalasi kamar operasi', 'Insiden tertinggalnya instrumen/kasa/benda lain saat operasi', '', '', '', 'P', '', '', 'Tertinggalnya instrumen/kasa/benda lain saat operasi adalah tertinggalnya benda-benda tersebut pada saat operasi yang diketahui beberapa waktu setelah operasi dilakukan.', '', null, null, '2', 'Jumlah tertinggalnya instrumen/kasa/benda lain saat operasi per bulan ', 'Total kejadian tertinggalnya instrumen/kasa/benda lain saat operasi per bulan ', '2', null, '(Jumlah tertinggalnya instrumen/kasa/benda lain saat operasi per bulan /Total kejadian tertinggalnya instrumen/kasa/benda lain saat operasi per bulan ) x 100%', '%', 'Status rekam medis pasien dan laporan insiden', null, '1', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('55', '55', '55', '4e17c866-6d29-11ec-a73f-1e544a7779f8', 'Instalasi kamar operasi', 'Keterlambatan waktu mulai operasi &gt; 30 menit', '', '', '', 'P', '', '', 'Insiden Kejadian Tertundanya Operasi Lebih Dari 30 menit', '', null, null, '2', 'Jumlah pasien yang operasinya tertunda 30 menit per bulan ', 'Jumlah pasien operasi dalam bulan tersebut ', '2', null, '(Jumlah pasien yang operasinya tertunda 30 menit per bulan /Jumlah pasien operasi dalam bulan tersebut ) x 100%', '%', 'Status rekam medis pasien', null, '2', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('56', '56', '56', '4e17ca10-6d29-11ec-a73f-1e544a7779f8', 'Intalasi rawat inap, Instalasi Pelayanan Intensif', 'Ketidakpatuhan pendokumentasian asesmen nyeri', '', '', '', 'P', '', '', 'Terjadinya ketidakpatuhan perawat dalam pendokumentasian asesmen nyeri secara kontinyu di status pasien baik asesmen awal maupun ulang.Semua pasien dengan keluhan nyeri', '', null, null, '2', 'Jumlah status pasien di ICU dengan keluhan nyeri yang tidak lengkap dokumentasi  asesmen nyerinya selama 1 bulan', 'Jumlah seluruh pasien yang dirawat di  ICU dengan keluhan nyeri dalam bulan tersebut', '2', null, '(Jumlah status pasien di ICU dengan keluhan nyeri yang tidak lengkap dokumentasi  asesmen nyerinya selama 1 bulan/Jumlah seluruh pasien yang dirawat di  ICU dengan keluhan nyeri dalam bulan tersebut) x 100%', '%', 'Rekam medis pasien', null, '5', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('57', '57', '57', '4e17cbae-6d29-11ec-a73f-1e544a7779f8', 'Instalasi Pelayanan Intensif', 'Insiden Kesalahan Setting Ventilator', '', '', '', 'P', '', '', 'Terjadinya Insiden pada pasien yang menyebabkan perubahan pada kondisi pasien akibat kesalahan setting pada ventilator yang di gunakan oleh pasien.', '', null, null, '2', 'Insiden Kesalahan Setting Ventilator ', 'Jumlah total Insiden Kesalahan Setting Ventilator dalam bulan tersebut', '2', null, '(Insiden Kesalahan Setting Ventilator /Jumlah total Insiden Kesalahan Setting Ventilator dalam bulan tersebut) x 100%', '%', 'Rekam medis dan laporan insiden', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('58', '58', '58', '4e17cd49-6d29-11ec-a73f-1e544a7779f8', 'Instalasi Pelayanan Intensif', 'Insiden Vagal Reflex Pada Pemasangan ET', '', '', '', 'P', '', '', 'Terjadinya Insiden yang menimbulkan reaksi&nbsp; terjadinya vagal reflek pada pasien akibat pemasangan ET.', '', null, null, '2', 'Jumlah Insiden  Vagal Reflek Pada Pemasangan ET', 'Jumlah total Insiden  Vagal Reflek Pada Pemasangan ET pada bulan tersebut', '2', null, '(Jumlah Insiden  Vagal Reflek Pada Pemasangan ET/Jumlah total Insiden  Vagal Reflek Pada Pemasangan ET pada bulan tersebut) x 100%', '%', 'Rekam medis dan laporan insiden', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('59', '59', '59', '4e17ceeb-6d29-11ec-a73f-1e544a7779f8', 'Instalasi farmasi rawat jalan', 'Keterlambatan waktu penerimaan obat racikan', '', '', '', '', '', '', 'Keterlambatan waktu penerimaan obat racikan pada pasien rawat jalan &gt; 60 menit setelah diterimanya resep oleh petugas instalasi farmasi rawat jalan.', '', null, null, '2', 'Jumlah pasien rawat jalan yang menerima obat racikan &ge; 60 menit per bulan', 'Jumlah pasien rawat jalan yang menerima resep obat racikan dalam bulan tersebut', '2', null, '(Jumlah pasien rawat jalan yang menerima obat racikan &ge; 60 menit per bulan/Jumlah pasien rawat jalan yang menerima resep obat racikan dalam bulan tersebut) x 100%', '%', 'Catatan keterlambatan penerimaan obat racikan di rawat jalan ', null, '3', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('60', '60', '60', '4e17d0a1-6d29-11ec-a73f-1e544a7779f8', 'Instalasi farmasi rawat jalan', 'Keterlambatan waktu penerimaan obat non racikan', '', '', '', '', '', '', 'Keterlambatan waktu penerimaan obat non racikan pada pasien rawat jalan &gt; 20 menit setelah diterimanya resep oleh petugas instalasi farmasi', '', null, null, '2', 'Jumlah pasien rawat jalan yang menerima obat non racikan > 20 menit ', 'Jumlah pasien rawat jalan yang menerima obat non racikan dalam bulan tersebut', '2', null, '(Jumlah pasien rawat jalan yang menerima obat non racikan > 20 menit /Jumlah pasien rawat jalan yang menerima obat non racikan dalam bulan tersebut) x 100%', '%', 'Catatan keterlambatan penerimaan obat non racikan di rawat jalan ', null, '3', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('61', '61', '61', '4e17d152-6d29-11ec-a73f-1e544a7779f8', 'Instalasi laboratorium ', 'Kesalahan penulisan jenis komponen darah pada kitir/label darah', '', '', '', 'P', '', '', 'Penulisan jenis komponen darah pada kitir/label darah yang diberikan kepada pasien tidak sesuai dengan jenis komponen darah yang di instruksikan atau permintaan dokter.', '', null, null, '2', 'Jumlah kesalahan penulisan jenis komponen pada label darah per bulan', 'Jumlah permintaan darah pada bulan tersebut', '2', null, '(Jumlah kesalahan penulisan jenis komponen pada label darah per bulan/Jumlah permintaan darah pada bulan tersebut) x 100%', '%', 'Catatan sensus harian', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('62', '62', '62', '4e17d1dc-6d29-11ec-a73f-1e544a7779f8', 'Instalasi laboratorium ', 'Kesalahan pemeriksaan golongan darah', '', '', '', 'P', '', '', 'Terjadinya kesalahan pemeriksaan golongan darah dimana hasil dari pemeriksaan golongan darah pasien tidak sesuai dengan golongan darah pasien yang sebenarnya', '', null, null, '2', 'Jumlah kesalahan pemeriksaan golongan darah per bulan', 'Jumlah semua pemeriksaan golongan darah dalam bulan tersebut', '2', null, '(Jumlah kesalahan pemeriksaan golongan darah per bulan/Jumlah semua pemeriksaan golongan darah dalam bulan tersebut) x 100%', '%', 'Catatan sensus harian', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('63', '63', '63', '4e17d375-6d29-11ec-a73f-1e544a7779f8', 'Instalasi laboratorium ', 'Kesalahan jenis komponen darah', '', '', '', 'P', '', '', 'Terjadinya kesalahan pemberian komponen darah pada pasien, atau pemberian tersebut tidak sesuai dengan jenis komponen darah yang di instruksikan atau permintaan dokter.', '', null, null, '2', 'Jumlah kesalahan jenis komponen darah yang diberikan perbulan', 'Jumlah permintaan darah pada bulan tersebut', '2', null, '(Jumlah kesalahan jenis komponen darah yang diberikan perbulan/Jumlah permintaan darah pada bulan tersebut) x 100%', '%', 'Catatan sensus harian', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('64', '64', '64', '4e17d3fd-6d29-11ec-a73f-1e544a7779f8', 'Instalasi rehabilitasi medis', 'Pasien rehabilitasi medis yang drop out', '', '', '', '', '', '', 'Pasien<em> drop out</em> terhadap pelayanan rehabilitasi yang direncanakan adalah pasien rawat jalan yang tidak meneruskan program rehabilitasi yang telah direncanakan', '', null, null, '2', 'Jumlah seluruh pasien yang drop out per bulan', 'Jumlah seluruh pasien yang diprogram rehabilitasi medis dalam bulan tersebut', '2', null, '(Jumlah seluruh pasien yang drop out per bulan/Jumlah seluruh pasien yang diprogram rehabilitasi medis dalam bulan tersebut) x 100%', '%', 'Buku register rehabilitasi medis', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('65', '65', '65', '4e17d485-6d29-11ec-a73f-1e544a7779f8', 'Unit hemodialisa', 'Keterlambatan waktu tindakan hemodialisa', '', '', '', 'P', '', '', 'Keterlambatan waktu tindakan hemodialisa adalah terjadinya penundaan waktu tindakan pasien hemodialisa lebih dari 1 jam dari waktu yang ditentukan (dijadwalkan).', '', null, null, '2', 'Jumlah keterlambatan waktu tindakan hemodialisa perbulan', 'Jumlah seluruh pasien hemodialisa dalam bulan tersebut', '2', null, '(Jumlah keterlambatan waktu tindakan hemodialisa perbulan/Jumlah seluruh pasien hemodialisa dalam bulan tersebut) x 100%', '%', 'Catatan keterlambatan pasien hemodialisa dan rekam medis', null, '1', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('66', '66', '66', '4e17d622-6d29-11ec-a73f-1e544a7779f8', 'Unit hemodialisa', 'Insiden kesalahan setting program hemodialisa', '', '', '', 'P', '', '', 'Kesalahan setting program mesin hemodialisa adalah terjadi ketidaksesuaian antara program dokter dengan program yang dilakukan sehingga dapat mempengaruhi kondisi pasien', '', null, null, '2', 'Jumlah kesalahan setting program hemodialisa perbulan ', 'Jumlah total kesalahan setting program hemodialisa dalam bulan tersebut', '2', null, '(Jumlah kesalahan setting program hemodialisa perbulan /Jumlah total kesalahan setting program hemodialisa dalam bulan tersebut) x 100%', '%', 'Catatan kesalahan setting program  pasien hemodialisa dan rekam medis', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('67', '67', '67', '4e17d6cb-6d29-11ec-a73f-1e544a7779f8', 'Unit hemodialisa', 'Insiden ketidaktepatan insersi vena dan arteri pada pasien hemodialisa', '', '', '', 'P', '', '', 'Ketidaktepatan insersi akses vena dan arteri adalah ketidaktepatan pelaksanaan akses intravaskuler baik vena maupun arteri perifer atau AV shunt.', '', null, null, '2', 'Jumlah ketidaktepatan insersi vena dan arteri perbulan', 'Jumlah total ketidaktepatan insersi vena dan arteri pada bulan tersebut', '2', null, '(Jumlah ketidaktepatan insersi vena dan arteri perbulan/Jumlah total ketidaktepatan insersi vena dan arteri pada bulan tersebut) x 100%', '%', 'Catatan keterlambatan pasien hemodialisa dan rekam medis', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('68', '68', '68', '4e17d869-6d29-11ec-a73f-1e544a7779f8', 'CSSD', 'Kegagalan Uji Bowie Dick', '', '', '', 'P', '', '', 'Uji Bowie Dick adalah uji yang dilakukan untuk memastikan apakah fungsi vakum pada mesin sterilisasi steam berfungsi secara optimal dalam menarik udara keluar chamber sehingga uap air dapat masuk dan melakukan proses sterilisasi.<br />\nDikatakan gagal apabila indikator Bowie Dick test pack tidak berubah warna dengan sempurna (warna asal putih berubah menjadi hitam sempurna)', '', null, null, '2', 'Angka kegagalan uji Bowie Dick pada mesin sterilisasi autoclave per bulan', 'Jumlah seluruh hasil uji Bowie Dick pada mesin sterilisasi autoclave pada bulan tersebut', '2', null, '(Angka kegagalan uji Bowie Dick pada mesin sterilisasi autoclave per bulan/Jumlah seluruh hasil uji Bowie Dick pada mesin sterilisasi autoclave pada bulan tersebut) x 100%', '%', 'Laporan unit', null, '1', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('69', '69', '69', '4e17d944-6d29-11ec-a73f-1e544a7779f8', 'Unit endoskopi', 'Keterlambatan waktu tindakan endoskopi', '', '', '', 'P', '', '', 'Keterlambatan waktu tindakan endoskopi adalah tertundanya tindakan endoscopy lebih dari 60 menit', '', null, null, '2', 'Jumlah tindakan endoskopi yang tertunda lebih dari 60 menit perbulan', 'Jumlah pasien yang dilakukan endoskopi dalam bulan tersebut ', '2', null, '(Jumlah tindakan endoskopi yang tertunda lebih dari 60 menit perbulan/Jumlah pasien yang dilakukan endoskopi dalam bulan tersebut ) x 100%', '%', 'Rekam medis', null, '3', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('70', '70', '70', '4e17dae2-6d29-11ec-a73f-1e544a7779f8', 'Unit endoskopi', 'Insiden vagal reflex pada tindakan gastroskopi', '', '', '', 'P', '', '', 'Adanya insiden vagal reflek pada pasien akibat tindakan gastroskopi', '', null, null, '2', 'Insiden vagal reflex pada tindakan endoskopi perbulan', 'Jumlah total insiden vagal reflex pada tindakan endoskopi pada bulan tersebut', '2', null, '(Insiden vagal reflex pada tindakan endoskopi perbulan/Jumlah total insiden vagal reflex pada tindakan endoskopi pada bulan tersebut) x 100%', '%', 'Laporan insiden', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('71', '71', '71', '4e17db6b-6d29-11ec-a73f-1e544a7779f8', 'Unit endoskopi', 'Insiden ruptur colon pada tindakan kolonoskopi', '', '', '', 'P', '', '', 'Adanya insiden yang menimbulkan&nbsp; terjadinya ruptur colon pada tindakan kolonoskopi', '', null, null, '2', 'Insiden ruptur colon pada tindakan kolonoskopi per bulan', 'Jumlah total insiden ruptur colon pada tindakan kolonoskopi dalam bulan tersebut', '2', null, '(Insiden ruptur colon pada tindakan kolonoskopi per bulan/Jumlah total insiden ruptur colon pada tindakan kolonoskopi dalam bulan tersebut) x 100%', '%', 'Laporan insiden', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('72', '72', '72', '4e17dbf3-6d29-11ec-a73f-1e544a7779f8', 'Instalasi radiologi', 'Kesalahan Posisi Pasien dalam Pemeriksaan Radiologi', '', '', '', 'P', '', '', 'Terjadinya kesalahan posisi pemeriksaan : dimana hasil tindakan pemeriksaan radiologi terhadap pasien tidak sesuai posisinya seperti yang diharapkan oleh dokter pengirim. Pemeriksaan radiologi antara lain : X-Ray, USG, CT Scan dan MRI', '', null, null, '2', 'Jumlah  kesalahan posisi pasien dalam pemeriksaan radiologi perbulan', 'Jumlah seluruh pemeriksaan radiologi dalam bulan tersebut', '2', null, '(Jumlah  kesalahan posisi pasien dalam pemeriksaan radiologi perbulan/Jumlah seluruh pemeriksaan radiologi dalam bulan tersebut) x 100%', '%', 'Laporan insiden', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('73', '73', '73', '4e17ddb1-6d29-11ec-a73f-1e544a7779f8', 'Instalasi radiologi', 'Kesalahan cetak film pada pemeriksaan&nbsp; radiologi<br />\n&nbsp;', '', '', '', 'P', '', '', 'Terjadinya kesalahan cetak film : dimana cetak film pemeriksaan radiologi tidak sesuai &nbsp;dengan hasil cetak film seperti yang diharapkan oleh dokter pengirim maupun dokter radiolog.<br />\n&nbsp;', '', null, null, '2', 'Jumlah kesalahan cetak film  pemeriksaan radiologi perbulan', 'Jumlah seluruh pemeriksaan radiologi dalam bulan tersebut', '2', null, '(Jumlah kesalahan cetak film  pemeriksaan radiologi perbulan/Jumlah seluruh pemeriksaan radiologi dalam bulan tersebut) x 100%', '%', 'Laporan bulanan radiologi', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('74', '74', '74', '4e17de49-6d29-11ec-a73f-1e544a7779f8', 'Instalasi Rekam Medis', 'Penomeran rekam medis ganda/dobel', '', '', '', 'P', '', '', 'Rekam medis adalah berisi catatan identitas pasien, anamneses, pengobatan, tindakan medis serta pelayanan lainnya yang diberikan selama di rumah sakit di rumah sakit.<br />\nYang disebut nomor rekam medis ganda adalah pemberian nomor rekam medis lebih dari satu yang diberikan kepada satu pasien, sehingga satu pasien mempunyai berkas rekam medis lebih dari satu.', '', null, null, '2', 'Penomeran rekam medis ganda/dobel per bulan', 'Jumlah pasien MRS dan jumlah pasien rawat jalan dalam bulan tersebut', '2', null, '(Penomeran rekam medis ganda/dobel per bulan/Jumlah pasien MRS dan jumlah pasien rawat jalan dalam bulan tersebut) x 100%', '%', 'Rekam medis pasien', null, '1', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('75', '75', '75', '4e17dfe1-6d29-11ec-a73f-1e544a7779f8', 'Instalasi Rekam Medis', 'Kehilangan dokumen rekam medis pasien rawat jalan', '', '', '', 'P', '', '', 'Rekam medis adalah berisi catatan identitas pasien, anamneses, pengobatan, tindakan medis serta pelayanan lainnya yang diberikan selama di rumah sakit di rumah sakit.<br />\nRekam medis yang hilang adalah berkas rekam medis yang tidak ditemukan pada saat sedang diperlukan, berkas rekam medis ini bisa terselip di tempat lain, dipinnjam untuk keperluan lain ataupun terbawa pasien.', '', null, null, '2', 'Kehilangan dokumen rekam medis pasien rawat jalan perbulan', 'Jumlah pasien rawat jalan dalam bulan teersebut', '2', null, '(Kehilangan dokumen rekam medis pasien rawat jalan perbulan/Jumlah pasien rawat jalan dalam bulan teersebut) x 100%', '%', 'Rekam medis pasien', null, '1', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('76', '76', '76', '4e17e176-6d29-11ec-a73f-1e544a7779f8', 'Kamar/ruang operasi', 'Angka kelengkapan pengisian surgical checklist di kamar operasi', '', '', '', 'P', '', '', 'Penerapan keselamatan operasi (PKO) adalah pengisian checklist keselamatan operasi pada form yang dilakukan oleh petugas meliputi &nbsp;:<br />\n1. Tahapan Sign-in<br />\ndilakukan sebelum induksi anestesi minimal dilakukan oleh perawat dan dokter anestesi<br />\n2. Tahapan Time-out<br />\ndilakukan sebelum insisi kulit, diisi oleh perawat, dokter anestesi dan operator<br />\n3. Tahapan Sign-out<br />\ndilakukan sebelum pasien meninggalkan kamar operasi/OK, di isi oleh perawat, dokter anestesi dan operator<br />\n&nbsp;<br />\nKriteria : sesuai kriteria WHO', '', null, null, '2', 'Jumlah pasien pembedahan di ruang operasi yang telah diisi lengkap checklist keselamatan pasiennya sesuai tahapan oleh petugas tertentu disertai tandatangan dan penulisan jam pengisian', 'Jumlah pasien pembedahan  di ruang operasi', '2', null, '(Jumlah pasien pembedahan di ruang operasi yang telah diisi lengkap checklist keselamatan pasiennya sesuai tahapan oleh petugas tertentu disertai tandatangan dan penulisan jam pengisian/Jumlah pasien pembedahan  di ruang operasi) x 100%', '%', 'Catatan data pasien operasi', null, '100', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('77', '77', '77', '4e17e311-6d29-11ec-a73f-1e544a7779f8', 'Rawat inap', 'Kepatuhan Penggunaan Formularium Nasional', '', '', '', 'P', '', '', 'Kepatuhan penggunaan Formularium Nasional (Fornas) adalah kesesuaian penulisan resep oleh DPJP dengan Formularium Nasional untuk Pasien JKN', '', null, null, '2', 'Jumlah item resep (R/) yang sesuai Fornas ', 'Jumlah total item resep (R/)', '2', null, '(Jumlah item resep (R/) yang sesuai Fornas /Jumlah total item resep (R/)) x 100%', '%', 'Rekam medis', null, '80', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('78', '78', '78', '4e17e3c1-6d29-11ec-a73f-1e544a7779f8', 'IGD', 'Kematian Pasien di IGD', '', '', '', '', 'O', '', 'Kematian pasien di IGD adalah kematian pasien yang terjadi dalam<br />\nperiode &le; 8 jam sejak pasien datang ke IGD', '', null, null, '2', 'jumlah pasien meninggal di IGD &le; 8 jam sejak datang ', 'jumlah seluruh pasien yang ditangani di IGD ', '2', null, '(jumlah pasien meninggal di IGD &le; 8 jam sejak datang /jumlah seluruh pasien yang ditangani di IGD ) x 100%', '%', 'Rekam medis', '2', '2.5', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('79', '79', '79', '4e17e56d-6d29-11ec-a73f-1e544a7779f8', 'Instalasi Rawat Inap', 'Kecepatan Respon Terhadap Komplaian (KRK)', '', '', '', '', 'O', '', 'Kecepatan respon terhadap komplain adalah kecepatan Rumah sakit<br />\ndalam &nbsp;menanggapi &nbsp;komplain &nbsp;baik &nbsp;tertulis, &nbsp;lisan&nbsp; atau &nbsp;melalui&nbsp; mass media&nbsp;&nbsp; &nbsp;yang&nbsp;&nbsp; &nbsp;sudah &nbsp;diidentifikasi&nbsp; tingkat &nbsp;risiko &nbsp;dan &nbsp;dampak &nbsp;risiko dengan penetapan grading/ dampak risiko berupa ekstrim (merah), Tinggi (kuning), Rendah (hijau), dan dibuktikan dengan data, dan tindak lanjut atas respon time komplain tersebut sesuai dengan kategorisasi/grading/dampak risiko.<br />\n&nbsp;<br />\nWarna Merah :<br />\ncenderung berhubungan dengan polisi, pengadilan, kematian, mengancam&nbsp; sistem/kelangsungan &nbsp;organisasi, &nbsp;poptensi&nbsp; kerugian material dll.<br />\nWarna Kuning :<br />\ncenderung berhubungan dengan pemberitaan media, potensi kerugian in material, dll.<br />\nWarna Hijau :<br />\ntidak menimbulkan kerugian berarti baik material maupun immaterial.<br />\n&nbsp;<br />\n&nbsp;<br />\nKriteria Penilaian :<br />\n1. Melihat data rekapitulasi komplain yang dikategorikan merah, kuning, hijau<br />\n2. Melihat data tindak lanjut komplain setiap kategori yang dilakukan dalam kurun waktu sesuai standar<br />\n3. Membuat persentase jumlah komplain yang ditindaklanjuti terhadap seluruh komplain disetiap kategori<br />\na. &nbsp;Komplain kategori merah (KKM) ditanggapi dan ditindaklanjuti maksimal 1x24 jam<br />\nb. &nbsp;Komplain kategori kuning (KKK) ditanggapi dan ditindaklanjuti maksimal 3 hari<br />\nc.&nbsp; &nbsp;Komplain kategori hijau (KKH) ditanggapi dan ditindaklanjuti maksimal 7 hari', '', null, null, '2', 'KKM + KKK + KKH (%)', 'Nilai Denominator = 3', '2', null, '(KKM + KKK + KKH (%)/Nilai Denominator = 3) x 100%', '%', 'Survey kepuasan pelanggan, Laporan, Rekapitulasi komplain/keluhan', null, '75', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('80', '80', '80', '4e17e718-6d29-11ec-a73f-1e544a7779f8', 'Instalasi farmasi', 'Ketidaktepatan billing resep obat pasien IGD', '', '', '', 'P', '', '', 'Ketidaktepatan entry billing resep&nbsp; pasien IGD yang tidak dirawat', '', null, null, '2', 'Jumlah pasien IGD yang tidak dirawat yang mengalami kesalahan billing resep perbulan', 'Jumlah seluruh pasien IGD yang tidak dirawat yang dilakukan billing resep dalam bulan tersebut', '2', null, '(Jumlah pasien IGD yang tidak dirawat yang mengalami kesalahan billing resep perbulan/Jumlah seluruh pasien IGD yang tidak dirawat yang dilakukan billing resep dalam bulan tersebut) x 100%', '%', 'Catatan kesalahan billing', null, '0.5', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('81', '81', '81', '4e17e8ae-6d29-11ec-a73f-1e544a7779f8', 'Seluruh unit pelayanan dalam rumah sakit', 'Keterlambatan waktu menangani kerusakan alat', '', '', '', 'P', '', '', 'Keterlambatan waktu menangani kerusakan alat adalah waktu yang dibutuhkan mulai laporan alat rusak diterima (lisan maupun tertulis)&nbsp; sampai dengan petugas melakukan pemeriksaan terhadap alat yang rusak untuk tindak lanjut perbaikan lebih dari 15 menit.', '', null, null, '2', 'Jumlah keterlambatan waktu menangani kerusakan alat perbulan', 'Jumlah seluruh laporan kerusakan alat dalam bulan tersebut', '2', null, '(Jumlah keterlambatan waktu menangani kerusakan alat perbulan/Jumlah seluruh laporan kerusakan alat dalam bulan tersebut) x 100%', '%', 'Laporan dari unit pemeliharaan sarana', null, '1', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('82', '82', '82', '4e17ea46-6d29-11ec-a73f-1e544a7779f8', 'Unit pemeliharaan sarana ', 'Keterlambatan respon time genset', '', '', '', 'P', '', '', 'Genset tidak menyala secara otomatis dalam waktu &lt; 10 detik pada saat listrik (PLN) padam.', '', null, null, '2', 'Jumlah kejadian genset menyala dalam waktu &gt; 10 detik pada saat listrik padam perbulan', 'Jumlah seluruh kejadian pemadaman listrik dalam bulan tersebut', '2', null, '(Jumlah kejadian genset menyala dalam waktu &gt; 10 detik pada saat listrik padam perbulan/Jumlah seluruh kejadian pemadaman listrik dalam bulan tersebut) x 100%', '%', 'Laporan dari unit pemeliharaan sarana', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('83', '83', '83', '4e17ec06-6d29-11ec-a73f-1e544a7779f8', 'Seluruh unit pelayanan', 'Linen hilang', '', '', '', '', '', '', 'Kejadian linen yang&nbsp; hilang di masing-masing unit', '', null, null, '2', 'Jumlah linen yang hilang perbulan', 'Jumlah seluruh linen dalam bulan tersebut', '2', null, '(Jumlah linen yang hilang perbulan/Jumlah seluruh linen dalam bulan tersebut) x 100%', '%', 'Catatan kehilangan linen', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('84', '84', '84', '4e17ee3e-6d29-11ec-a73f-1e544a7779f8', 'Instalasi laboratorium ', 'Ketidaktepatan administrasi keuangan laboratorium', '', '', '', '', '', '', 'Angka yang menunjukkan ketidaktepatan pelayanan administrasi keuangan laboratorium: kesalahan biling, ketidaklengkapan biling', '', null, null, '2', 'Jumlah ketidaktepatan administrasi keuangan laboratorium perbulan', 'Jumlah pelayanan administrasi keuangan dalam bulan tersebut', '2', null, '(Jumlah ketidaktepatan administrasi keuangan laboratorium perbulan/Jumlah pelayanan administrasi keuangan dalam bulan tersebut) x 100%', '%', 'Catatan sensus harian', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('85', '85', '85', '4e17efe0-6d29-11ec-a73f-1e544a7779f8', 'Bagian Keuangan', 'Ketidaklengkapan dokumen pendukung penagihan', '', '', '', '', '', '', 'Dokumen pendukung penagihan adalah dokumen yang harus disertakan didalam proses penagihan pada pihak asuransi / perusahaan sesuai dengan permintaan yang tercantum didalam surat perjanjian kerjasama.', '', null, null, '2', 'Jumlah ketidaklengkapan dokumen pendukung penagihan perbulan', 'Jumlah seluruh tagihan atas pelayanan rumah sakit yang terkirim dalm bulan tersebut', '2', null, '(Jumlah ketidaklengkapan dokumen pendukung penagihan perbulan/Jumlah seluruh tagihan atas pelayanan rumah sakit yang terkirim dalm bulan tersebut) x 100%', '%', 'Bagian Keuangan', null, '1', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('86', '86', '86', '4e17f183-6d29-11ec-a73f-1e544a7779f8', 'Humas dan Pelayanan Pelanggan', 'Tidak terisinya Angket Kepuasan Pasien Rawat Inap', '', '', '', 'P', '', '', 'Tidak terisinya angket kepuasan rawat inap adalah jumlah angket yang tidak kembali atau kembali dalam keadaan tidak terisi kepada petugas humas dan pelayanan pelanggan', '', null, null, '2', 'Jumlah angket kepuasan yang tidak kembali atau tidak terisi selama satu bulan', 'Jumlah angket kepuasan yang dibagikan dalam bulan tersebut', '2', null, '(Jumlah angket kepuasan yang tidak kembali atau tidak terisi selama satu bulan/Jumlah angket kepuasan yang dibagikan dalam bulan tersebut) x 100%', '%', 'Sub Bagian Humas dan Pelayanan Pelanggan', null, '25', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('87', '87', '87', '4e17f386-6d29-11ec-a73f-1e544a7779f8', 'EDP', 'Keterlambatan waktu penanganan kerusakan hardware / jaringan', '', '', 'I', '', '', '', 'Angka yang menunjukkan keterlambatan respon petugas EDP dalam menanggapi laporan kerusakan hardware / jaringan, yaitu lebih dari 1 jam sejak laporan kerusakan diterima&nbsp; sampai dengan petugas EDP datang ke unit yang bersangkutan.', '', null, null, '2', 'Jumlah keterlambatan respon time petugas EDP dalam menanggapi laporan kerusakan hardware / jaringan pada bulan tersebut', 'Jumlah seluruh laporan kerusakan hardware / jaringan pada bulan tersebut', '2', null, '(Jumlah keterlambatan respon time petugas EDP dalam menanggapi laporan kerusakan hardware / jaringan pada bulan tersebut/Jumlah seluruh laporan kerusakan hardware / jaringan pada bulan tersebut) x 100%', '%', 'Buku laporan kerusakan hardware / jaringan', null, '0', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('88', '88', '88', '4e17f580-6d29-11ec-a73f-1e544a7779f8', 'Logistik', 'Ketidaksesuaian surat pesanan (SP) dengan fisik barang / bahan', '', '', 'I', 'P', '', '', 'Ketidaksesuaian antara spesifikasi barang / bahan yang tertera di dalam surat pesanan dengan spesifikasi fisik barang / bahan yang diterima', '', null, null, '2', 'Ketidaksesuaian surat pesanan (SP) dg fisik barang/ bahan yg diterima per bulan', 'Jumlah surat pesanan barang yang dikirim dalam bulan tersebut', '2', null, '(Ketidaksesuaian surat pesanan (SP) dg fisik barang/ bahan yg diterima per bulan/Jumlah surat pesanan barang yang dikirim dalam bulan tersebut) x 100%', '%', 'Laporan pemesanan dan penerimaan barang', null, '1', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('89', '89', '89', '4e17f9c0-6d29-11ec-a73f-1e544a7779f8', 'Urusan kendaraan', 'Keterlambatan Pelayanan Ambulans di Rumah Sakit', '', '', '', 'P', '', '', 'Keterlambatan pelayanan ambulans adalah keterlambatan merespon permintaan ambulans lebih dari 15 menit. Keterlambatan dihitung mulai telepon permintaan ambulans diterima sampai dengan ambulans siap berangkat.', '', null, null, '2', 'Jumlah keterlambatan pelayanan ambulans perbulan', 'Jumlah seluruh permintaan ambulans dalam bulan tersebut', '2', null, '(Jumlah keterlambatan pelayanan ambulans perbulan/Jumlah seluruh permintaan ambulans dalam bulan tersebut) x 100%', '%', 'Laporan pelayanan ambulans', null, '3', '', 'IKARS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('90', '90', '90', '4e17fa5d-6d29-11ec-a73f-1e544a7779f8', '', 'Kepatuhan Identifikasi Pasien', '', '', '', 'P', '', '', 'Identifikasi pasien adalah proses pengecekan identitas pasien menggunakan minimal 2 identitas dari 3 identitas yang tercantum pada gelang, label atau bentuk identitas lainnya sebelum memberikan pelayanan sesuai dengan regulasi yang berlaku di rumah sakit.<br />\n&nbsp;<br />\nDisebut patuh bila proses identifikasi pasien dilakukan secara benar oleh petugas pada saat,&nbsp; antara lain :\n<ol>\n	<li>pemberian obat</li>\n	<li>pemberian pengobatan termasuk nutrisi</li>\n	<li>pemberian darah dan produk darah</li>\n	<li>pengambilan specimen</li>\n	<li>sebelum melakukan tindakan diagnostik / therapeutic.</li>\n</ol>\n&nbsp;<br />\nPengukuran dilakukan terpisah untuk masing-masing proses tersebut diatas dan menghasilkan lima sub indikator yaitu:\n<ol>\n	<li>Kepatuhan pengecekan identitas pasien sebelum pemberian obat</li>\n	<li>Kepatuhan pengecekan identitas pasien sebelum pengobatan termasuk pemberian nutrisi pada diet khusus</li>\n	<li>Kepatuhan pengecekan identitas pasien sebelum pemberian transfusi darah dan produk darah.</li>\n	<li>Kepatuhan pengecekan identitas pasien sebelum pengambilan spesimen pemeriksaan</li>\n</ol>\nKepatuhan pengecekan identitas pasien sebelum melakukan tindakan diagnostik ( contoh: pungsi lumbal, endoskopi dsb) dan terapi (operasi, debridement dll)', '', null, null, '2', 'Jumlah proses yang telah dilakukan identifikasi secara benar', 'Jumlah proses pelayanan yang di observasi ', '2', null, '(Jumlah proses yang telah dilakukan identifikasi secara benar/Jumlah proses pelayanan yang di observasi ) x 100%', '%', 'sensus pada saat pengambilan data/ observasi', null, '100', '', 'IRS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('91', '91', '91', '4e17fb05-6d29-11ec-a73f-1e544a7779f8', '', 'Emergency Respon Time (Waktu Tanggap Pelayanan Gawatdarurat &le; 5 menit).', '', '', '', 'P', '', '', 'Emergency Response Time (Waktu tanggap) adalah waktu yang dibutuhkan mulai pasien dilakukan Triage di IGD sampai mendapat pelayanan dokter.<br />\nTriage adalah usaha pemilahan pasien sebelum ditangani berdasarkan tingkat kegawatdaruratan/trauma/penyakit dengan mempertimbangkan prioritas penanganan dan sumber daya yang ada.', '', null, null, '2', 'Jumlah pasien gawat, darurat, dan gawat-darurat yang mendapatkan pelayanan kegawatdaruratannya dalam waktu ? 5 menit.', 'Jumlah seluruh pasien pasien gawat, darurat, dan gawat-darurat yang mendapatkan pelayanan kegawatdaruratan di rumah sakit tersebut', '2', null, '(Jumlah pasien gawat, darurat, dan gawat-darurat yang mendapatkan pelayanan kegawatdaruratannya dalam waktu ? 5 menit./Jumlah seluruh pasien pasien gawat, darurat, dan gawat-darurat yang mendapatkan pelayanan kegawatdaruratan di rumah sakit tersebut) x 10', '%', 'Sensus harian', null, '100', '', 'IRS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('92', '92', '92', '4e17fbc2-6d29-11ec-a73f-1e544a7779f8', '', 'Waktu Tunggu Rawat Jalan', '', '', '', 'P', '', '', 'Waktu tunggu adalah waktu yang diperlukan mulai pasien kontak dengan petugas pendaftaran sampai dilayani oleh dokter/ dokter spesialis.<br />\nCatatan:<br />\nYang dimaksud&nbsp; kontak dengan petugas pendaftaran adalah waktu petugas mencatat identitas pasien.<br />\nYang dimaksud dilayani oleh dokter/ dokter spesialis adalah waktu pasien kontak awal dengan dokter/ dokter spesialis', '', null, null, '2', 'Jumlah kumulatif waktu tunggu pasien rawat jalan yang disurvey', 'Jumlah seluruh pasien rawat jalan yang disurvey', '2', null, '(Jumlah kumulatif waktu tunggu pasien rawat jalan yang disurvey/Jumlah seluruh pasien rawat jalan yang disurvey) x 1menit', 'menit', 'Formulir pengambilan data rawat jalan ', null, '60', '', 'IRS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('93', '93', '93', '4e17fc60-6d29-11ec-a73f-1e544a7779f8', '', 'Penundaan Operasi Elektif', '', '', '', '', '', '', 'Penundaan operasi elektif adalah perubahan jadwal operasi yang direncanakan.<br />\nOperasi Elektif adalah operasi atau tindakan yang dijadwalkan.&nbsp;<br />\nTindakan operasi elektif termasuk mata, paru&nbsp;', '', null, null, '2', 'Jumlah pasien yang waktu jadwal operasinya berubah', 'Jumlah pasien operasi elektif', '2', null, '(Jumlah pasien yang waktu jadwal operasinya berubah/Jumlah pasien operasi elektif) x 100%', '%', 'Data pasien yang dijadwalkan operasi dan data pelaksanaan operasi. Data kamar operasi, kamar tindaka', null, '5', '', 'IRS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('94', '94', '94', '4e17fcfb-6d29-11ec-a73f-1e544a7779f8', '', 'Kepatuhan Jam Visite Dokter Spesialis', '', '', '', '', '', '', 'Kepatuhan Jam Visite Dokter Spesialis sebagai DPJP adalah kunjungan dokter spesialis untuk melihat perkembangan pasien yang menjadi tanggung jawabnya setiap hari sebelum jam 14.00 termasuk hari libur.<br />\n&nbsp;<br />\nCatatan :<br />\n1.pasien baru masuk<br />\n2.batasan pukul 14.00<br />\n3.hari libur<br />\n4. RS. Swasta', '', null, null, '2', 'Jumlah visite dokter spesialis sebelum jam 14:00 pada hari berjalan', 'Jumlah visite dokter spesialis pada hari berjalan', '2', null, '(Jumlah visite dokter spesialis sebelum jam 14:00 pada hari berjalan/Jumlah visite dokter spesialis pada hari berjalan) x 100%', '%', 'Laporan Visite Rawat Inap dalam rekam medik ', null, '80', '', 'IRS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('95', '95', '95', '4e17fe52-6d29-11ec-a73f-1e544a7779f8', '', 'Waktu Lapor Hasil Tes Kritis laboratorium', '', '', '', '', '', '', 'Waktu lapor hasil tes kritis laboratorium adalah waktu yang diperlukan untuk memberikan jawaban kepada dokter yang mengirim setelah keluar hasil pemeriksaan dan mulai dibaca oleh Dokter/ Analis Laboratorium sampai hasilnya diterima oleh dokter yang mengirim<br />\n(lisan atau tulisan).<br />\n&nbsp;<br />\nStandar : harus diterima oleh dokter yang mengirim dalam waktu kurang dari 30 (tiga puluh) menit baik secara lisan maupun tulisan<br />\n&nbsp;<br />\nYang dimaksud dengan kritis adalah adalah hasil pemeriksaan yang termasuk dalam kategori kritis yang ditetapkan dengan kebijakan RS.<br />\nRED Category Condition adalah keadaan yang masuk dalam kondisi<br />\nkategori kritis atau yang memerlukan penatalaksanaan segera<br />\nWaktu tunggu yang memanjang dapat berakibat:\n<ul>\n	<li>Menurunkan kepercayaan terhadap layanan laboratorium</li>\n</ul>\nMemperpanjang diagnosa dan terapi penderita', '', null, null, '2', 'Jumlah pemeriksaan laboratorium kritis yang dilaporkan < 30 menit', 'Jumlah seluruh pemeriksaan laboratorium kritis', '2', null, '(Jumlah pemeriksaan laboratorium kritis yang dilaporkan < 30 menit/Jumlah seluruh pemeriksaan laboratorium kritis) x 100%', '%', 'Catatan data Instalasi Laboratorium ; Rekam Medik', null, '100', '', 'IRS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('96', '96', '96', '4e17ff12-6d29-11ec-a73f-1e544a7779f8', '', 'Kepatuhan Penggunaan Formularium Nasional Bagi RS Provider BPJS', '', '', '', '', '', '', 'Kepatuhan Penggunaan Formularium Nasional adalah kepatuhan para dokter meresepkan obat kepada pasien sesuai dengan daftar obat-obatan Formularium Nasional.<br />\nDisebut patuh bila seluruh obat dalam resep mengikuti formularium nasional', '', null, null, '2', 'Jumlah R/ yang patuh dengan formularium nasional', 'Jumlah seluruh R/', '2', null, '(Jumlah R/ yang patuh dengan formularium nasional/Jumlah seluruh R/) x 100%', '%', 'Lembar resep di Instalasi Farmasi', null, '80', '', 'IRS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('97', '97', '97', '4e17ffa9-6d29-11ec-a73f-1e544a7779f8', '', 'Kepatuhan Penggunaan Formularium RS Non Provider BPJS', '', '', '', '', '', '', 'Kepatuhan Penggunaan Formularium RS adalah kepatuhan para dokter meresepkan obat kepada pasien sesuai dengan daftar obat-obatan Formularium RS.<br />\nDisebut patuh bila seluruh obat dalam resep mengikuti formularium RS.', '', null, null, '2', 'Jumlah R/ yang patuh dengan formularium RS', 'Jumlah seluruh R/', '2', null, '(Jumlah R/ yang patuh dengan formularium RS/Jumlah seluruh R/) x 100%', '%', 'Lembar resep di Instalasi Farmasi', null, '80', '', 'IRS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('98', '98', '98', '4e180105-6d29-11ec-a73f-1e544a7779f8', '', 'Kepatuhan Cuci Tangan', '', '', '', '', '', '', 'Kebersihan tangan (<em>hand hygiene</em>) adalah segala usaha yang dilakukan untuk membersihkan kotoran yang secara kasat mata terlihat dan pengangkatan mikroorganisme yang tinggal sementara di tangan dengan menggunakan sabun dan air mengalir (<em>hand wash</em>) atau dengan cairan berbasis alkohol (<em>handrub</em>) dalam 6 langkah (WHO,2009)<br />\n&nbsp;<br />\nAudit kebersihan tangan adalah prosedur penilaian kepatuhan petugas melakukan kebersihan tangan sesuai 5 indikasi dari WHO yaitu sebelum kontak dengan pasien, setelah kontak dengan pasien, sebelum melakukan tindakan invasif dan aseptik, setelah kontak dengan cairan tubuh, dan setelah&nbsp; kontak dengan lingkungan dengan menjalankan 6 tahap teknik melakukan kebersihan tangan.<br />\n&nbsp;<br />\nLima indikasi kebersihan tangan:&nbsp;\n<ol>\n	<li>Sebelum kontak dengan pasien, yaitu sebelum masuk ruangan perawatan pasien&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</li>\n	<li>Kontak dengan pasien meliputi menyentuh tubuh pasien, baju atau pakaian&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</li>\n	<li>Prosedur aseptik contoh: tindakan transfusi, perawatan luka, pemasangan kateter urin, <em>suctioning</em>, perawatan daerah tindakan invasif</li>\n	<li>Tindakan invasif contohnya pemasangan kateter intravena (vena pusat/ vena perifer), kateter arteri</li>\n	<li>Cairan tubuh pasien seperti muntah, darah, nanah, urin, feces, produksi drain, dll&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</li>\n	<li>Menyentuh lingkungan meliputi: menyentuh tempat tidur pasien, linen yang terpasang di tempat tidur, alat-alat di sekitar pasien atau peralatan lain yang digunakan pasien, kertas/lembar untuk menulis yang ada di sekitar pasien</li>\n</ol>\n&nbsp;<br />\nEnam langkah teknik melakukan kebersihan tangan sesuai WHO\n<ol>\n	<li>Ratakan dan gosokkan sabun dengan kedua telapak tangan</li>\n	<li>Gosok punggung dan sela-sela jari tangan kiri dengan tangan kanan dan sebaliknya</li>\n	<li>Gosok kedua telapak dan sela-sela jari</li>\n	<li>Jari-jari sisi dalam dari kedua tangan saling mengunci</li>\n	<li>Gosok ibu jari kiri berputar dalam genggaman tangan kanan dan lakukan sebaliknya</li>\n	<li>Gosokkan dengan memutar ujung jari&ndash;jari tangan kanan di telapak tangan kiri dan sebaliknya, telapak tangan kiri dan sebaliknya&nbsp;&nbsp;</li>\n</ol>\n&nbsp;<br />\nPetugas yang dinilai mencakup SEMUA PETUGAS yang bertugas di ruangan (dokter, perawat, peserta didik, pekarya, cleaning service)', '', null, null, '2', 'Total kebersihan tangan yang dilakukan', 'Peluang kebersihan tangan', '2', null, '(Total kebersihan tangan yang dilakukan/Peluang kebersihan tangan) x 100%', '%', 'Catatan data dan pengamatan kebersihan tangan di semua unit pelayanan pasien', null, '85', '', 'IRS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('99', '99', '99', '4e180269-6d29-11ec-a73f-1e544a7779f8', '', 'Kepatuhan Upaya Pencegahan Risiko Cedera Akibat Pasien Jatuh pada pasien Rawat Inap', '', '', '', '', '', '', 'Upaya pencegahan jatuh meliputi :\n<ol>\n	<li>Screening di rawat jalan/ IGD</li>\n	<li>Asesmen awal risiko jatuh</li>\n</ol>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Asesmen Awal risiko jatuh adalah&hellip;&hellip;&hellip;&hellip;.\n\n<ol>\n	<li>Assesment Ulang risiko jatuh</li>\n</ol>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Asesmen Ulang risiko jatuh adalah&hellip;&hellip;.\n\n<ol>\n	<li>Edukasi pencegahan pasien jatuh.</li>\n</ol>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Edukasi pencegahan pasien jatuh adalah&hellip;&hellip;&hellip;..<br />\n&nbsp;<br />\nDisebut patuh apabila melaksanakan seluruh upaya pencegahan jatuh pada pasien yang berisiko sesuai dengan standar yang ditetapkan oleh rs.<br />\n&nbsp;<br />\nCatatan :\n<ol>\n	<li>Assessment awal hanya dilakukan pada pasien rawat inap</li>\n	<li>Untuk pasien rawat jalan dan IGD hanya dilakukan screening&nbsp;</li>\n</ol>\n', '', null, null, '2', 'Jumlah kasus yang mendapatkan ketiga upaya pencegahan pasien jatuh', 'Jumlah kasus semua pasien yang berisiko jatuh', '2', null, '(Jumlah kasus yang mendapatkan ketiga upaya pencegahan pasien jatuh/Jumlah kasus semua pasien yang berisiko jatuh) x 100%', '%', 'Rekam Medis pasien rawat inap', null, '100', '', 'IRS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('100', '100', '100', '4e18032d-6d29-11ec-a73f-1e544a7779f8', '', 'Kepatuhan Terhadap Clinical Pathway', '', '', '', '', '', '', 'Kepatuhan terhadap clinical pathway adalah kepatuhan para staf medis/ DPJP dalam menggunakan clinical pathway untuk memberikan asuhan klinis pasien secara terstandarisasi dan terintegrasi sehingga dapat meminimalkan adanya variasi proses asuhan klinis.<br />\nSetiap RS menetapkan 5 clinical pathway untuk penyakit atau kondisi yang memenuhi satu atau lebih kriteria yang berlaku di RS tersebut berdasarkan:<br />\na.Penyakit atau kondisi yang paling sering atau banyak terjadi (High Volume)<br />\nb.Penyakit atau kondisi yang memiliki risiko tinggi (High Risk)<br />\nc.Penyakit atau kondisi yang memerlukan biaya tinggi (High Cost)<br />\nd.Penyakit atau kondisi yang terdapat variasi/keragaman dalam pengelolaannya.<br />\nSetiap CP mampu menunjukan komponen standar LOS, obat dan penunjang.<br />\nDisebut patuh apabila mengikuti ketiga proses asuhan yang telah distandarisasi dalam CP', '', null, null, '2', 'Jumlah kasus yang penanganannya patuh dengan kriteria 5 clinical pathways', 'Jumlah total kasus yang  masuk dalam kriteria 5 clinical pathways yang ditetapkan', '2', null, '(Jumlah kasus yang penanganannya patuh dengan kriteria 5 clinical pathways/Jumlah total kasus yang  masuk dalam kriteria 5 clinical pathways yang ditetapkan) x 100%', '%', 'Format clinical pathways yang telah terisi ', null, '80', '', 'IRS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('101', '101', '101', '4e180445-6d29-11ec-a73f-1e544a7779f8', '', 'Kepuasan Pasien dan Keluarga', '', '', '', '', '', '', '<ul>\n	<li>Kepuasan adalah pernyataan tentang persepsi pelanggan terhadap jasa pelayanan kesehatan yang diberikan oleh RS. Kepuasan pelanggan dapat dicapai apabila pelayanan yang diberikan sesuai atau melampaui harapan pelanggan. Hal ini dapat diketahui dengan melakukan survei kepuasan pelanggan untuk mengetahui tingkat kepuasan pelanggan dengan mengacu pada kepuasan pelanggan berdasarkan Indeks Kepuasan Masyarakat (IKM).</li>\n	<li>Pemantauan dan pengukuran Kepuasan Pasien dan Keluarga adalah&nbsp; kegiatan untuk mengukur tingkatan kesenjangan pelayanan RS yang diberikan dengan harapan pasien dan keluarga&nbsp; di Rawat Jalan, Rawat Inap dan Gawat Darurat</li>\n	<li>Kepuasan Pasien keluarga&nbsp; diukur dengan mendapatkan gambaran persepsi pasien dan keluarga&nbsp; pada saat mendapatkan pengalaman selama dilayani di RS melalui :</li>\n	<li>metode kuesioner&nbsp; atau interview dengan konversi Rentang angka *Tidak Puas* &nbsp;sampai &nbsp;*Puas* &agrave; 1 &ndash; 5</li>\n	<li>Jumlah Responden berdasarkan sampling pasien Rawat Jalan/ Rawat Inap dan Gawat Darurat</li>\n	<li>Pelayanan yang diukur berdasarkan persepsi dan pengalaman pasien terhadap:</li>\n	<li>Fasilitas : Sarana, Prasarana, Alat</li>\n	<li>SDM : &nbsp;Perawat, Dokter, Petugas Lain</li>\n	<li>Farmasi : Kecepatan, Sikap Petugas, Penjelasan Penggunaan Obat</li>\n	<li>Service &agrave; Pendaftaran, Ruang Tunggu dan Pelayanan: , kecepatan, Kemudahan, Kenyamanan</li>\n	<li>Pengambilan kuesioner &agrave; sesuai Kebijakan RS minimal 1x per semester dan dilaksanakan oleh internal/ eksternal RS</li>\n</ul>\nPengukuran IKM dilaksanakan di lokasi layanan sesuai dengan metode dan ketentuan sebagaimana diatur dalam pedoman umum penyusunan Indeks Kepuasan Masyarakat unit layanan instansi pemerintah.', '', null, null, '2', 'Hasil Penilaian IKM.  Jumlah kumulatif hasil penilaian kepuasan dari pasien yang disurvei (dalam prosen)', 'Skala Maksimal Penilaian IKM.  Jumlah total pasien yang disurvei (n minimal 50)', '2', null, '(Hasil Penilaian IKM.  Jumlah kumulatif hasil penilaian kepuasan dari pasien yang disurvei (dalam prosen)/Skala Maksimal Penilaian IKM.  Jumlah total pasien yang disurvei (n minimal 50)) x 100%', '%', 'Hasil Kuesioner dan Rekapitulasi Hasil Kuesioner Hasil Survei', null, '80', '', 'IRS');
INSERT INTO `kalmut_katalogmutu_deskripsi` VALUES ('102', '102', '102', '4e180516-6d29-11ec-a73f-1e544a7779f8', '', 'Kecepatan respon Terhadap Komplain', '', '', '', '', '', '', 'Kecepatan respon terhadap komplain adalah kecepatan Rumah sakit dalam menanggapi komplain baik tertulis, lisan atau melalui mass media yang sudah diidentifikasi tingkat risiko dan dampak risiko dengan penetapan grading/ dampak risiko berupa ekstrim (merah), Tinggi (kuning), Rendah (hijau), dan dibuktikan dengan data, dan tindak lanjut atas respon time komplain tersebut sesuai dengan kategorisasi/grading/dampak risiko.<br />\n<strong>Warna Merah:</strong><br />\ncenderung berhubungan dengan polisi, pengadilan, kematian, mengancam sistem/kelangsungan organisasi, poptensi kerugian material dll.<br />\n<strong>Warna Kuning</strong>:<br />\ncenderung berhubungan dengan pemberitaan media, potensi kerugian in material, dll.<br />\n<strong>Warna Hijau:</strong><br />\ntidak menimbulkan kerugian berarti baik material maupun immaterial.<br />\nKriteria Penilaian :<br />\n1. Melihat data rekapitulasi komplain yang dikategorikan merah, kuning, hijau<br />\n2. Melihat data tindak lanjut komplain setiap kategori yan dilakukan dalam kurun waktu sesuai standar<br />\n3. Membuat persentase jumlah komplain yang ditindaklanjuti terhadap&nbsp; seluruh komplain disetiap kategori\n<ol>\n	<li>Komplain kategori merah (KKM) ditanggapi dan ditindaklanjuti maksimal 1x24 jam</li>\n	<li>Komplain kategori kuning (KKK) ditanggapi dan ditindaklanjuti maksimal 3 hari</li>\n</ol>\nKomplain kategori hijau (KKH) ditanggapi dan ditindaklanjuti maksimal 7 hari', '', null, null, '2', 'Jumlah KKM, KKK dan KKH yang sudah ditanggapi dan ditindaklanjuti', 'Jumlah seluruh KKM, KKK dan KKH', '2', null, '(Jumlah KKM, KKK dan KKH yang sudah ditanggapi dan ditindaklanjuti/Jumlah seluruh KKM, KKK dan KKH) x 100%', '%', 'Jumlah seluruh KKM, KKK dan KKH', null, '75', '', 'IRS');
